var suggestions=document.getElementById('suggestions');var userinput=document.getElementById('userinput');document.addEventListener('keydown',inputFocus);function inputFocus(e){if(e.keyCode===191){e.preventDefault();userinput.focus();}
if(e.keyCode===27){userinput.blur();suggestions.classList.add('d-none');}}
document.addEventListener('click',function(event){var isClickInsideElement=suggestions.contains(event.target);if(!isClickInsideElement){suggestions.classList.add('d-none');}});document.addEventListener('keydown',suggestionFocus);function suggestionFocus(e){const focusableSuggestions=suggestions.querySelectorAll('a');const focusable=[...focusableSuggestions];const index=focusable.indexOf(document.activeElement);let nextIndex=0;if(e.keyCode===38){e.preventDefault();nextIndex=index>0?index-1:0;focusableSuggestions[nextIndex].focus();}
else if(e.keyCode===40){e.preventDefault();nextIndex=index+1<focusable.length?index+1:index;focusableSuggestions[nextIndex].focus();}}
(function(){var index=new FlexSearch({preset:'score',cache:true,doc:{id:'id',field:['title','description','content',],store:['href','title','description',],},});var docs=[{id:0,href:"https://hackartists.github.io/infra/introduction/",title:"Infrastructure",description:"This page introduces infrastructure.",content:"\u003cp\u003e서비스를 출시하기 위한 배포 환경을 만드는 과정으로, 서비스, 모니터링 등이 잘 구동될 수 있는 환경 구축\u003c/p\u003e\n\u003ch2 id=\"주요-역할\"\u003e주요 역할\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e라우터, 데이터센터 등 다양한 하드웨어 관리\u003c/li\u003e\n\u003cli\u003eFirewall, 인터넷 상태 등의 네트워크 관리\u003c/li\u003e\n\u003cli\u003e각 서비스 및 서버에 대한 플랫폼 관리\u003c/li\u003e\n\u003cli\u003e각 서비스 및 소프트웨어 관리\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"주요-스킬\"\u003e주요 스킬\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e자동화 스크립트 개발\u003c/li\u003e\n\u003cli\u003e리스크 분석 능력\u003c/li\u003e\n\u003cli\u003e네트워크 모니터링 및 분석 능력\u003c/li\u003e\n\u003cli\u003e프로세스 수립 능력\u003c/li\u003e\n\u003c/ul\u003e\n"},{id:1,href:"https://hackartists.github.io/design/uml/usecase-diagram/",title:"유즈케이스(Usecase) 다이어그램",description:"This page explains how to draw usecase diagram with plantuml.",content:"\u003ch2 id=\"유즈케이스-다이어그램이란\"\u003e유즈케이스 다이어그램이란?\u003c/h2\u003e\n\u003ch3 id=\"정의-및-목적\"\u003e정의 및 목적\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e유즈케이스 다이어그램은 사용자 간의 상호동작(interaction)을 표현\n\u003cul\u003e\n\u003cli\u003e사용자가 수행할 수 있는 기능\u003c/li\u003e\n\u003cli\u003e사용자와 시스템간의 상호동작 관계\u003c/li\u003e\n\u003cli\u003e기능간의 상호동작 관계\u003c/li\u003e\n\u003cli\u003e사용자와 다른 사용자간의 상호동작 관계\n\u003cul\u003e\n\u003cli\u003e다른 사용자란 시스템상에서 정의된 서로 다른 타입의 사용자를 의미\n\u003cul\u003e\n\u003cli\u003e예로, 서비스 사용자와 시스템 관리자 또는 판매자와 구매자 등을 의미\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"유즈케이스-다이어그램\"\u003e유즈케이스 다이어그램\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e간단한 온라인 식물 쇼핑몰에 대한 유즈케이스 다이어그램 예제\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-usecase.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch2 id=\"유즈케이스-다이어그램-그리기\"\u003e유즈케이스 다이어그램 그리기\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"https://plantuml.com/ko/\"  target=\"_blank\" rel=\"noopener\"\n    \u003ePlant UML\u003c/a\u003e 을 이용하여 간단하게 그릴 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"사용자-및-기능-정의\"\u003e사용자 및 기능 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e시스템 관점에서의 사용자 타입 정의\u003c/li\u003e\n\u003cli\u003e각 사용자 관점에서의 기능 정의\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\n\n:서비스 사용자:  as user \u0026lt;\u0026lt; User \u0026gt;\u0026gt;\n:시스템 관리자:  as adm \u0026lt;\u0026lt; Admin \u0026gt;\u0026gt;\n\n(회원가입) as su\n(로그인) as si\n(식물구경) as po\n(식물구매) as pp\n(장바구니) as bk\n(식물업로드) as pu\n(결제) as pay\n(결제내역 확인) as pl\n(배송 조회) as delivery\n\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-usecase-comps.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch4 id=\"문법-설명\"\u003e문법 설명\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eskinparam backgroundcolor transparent\u003c/code\u003e 는 배경색을 투명으로 설정\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e:사용자 타입:\u003c/code\u003e 콜론을 중심으로 사용자의 이름을 입력\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eas xx\u003c/code\u003e 는 정의된 사용자를 뒤에서는 \u003ccode\u003exx\u003c/code\u003e 라는 키워드로 사용\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e\u0026lt;\u0026lt; type \u0026gt;\u0026gt;\u003c/code\u003e 추가적인 사용자에 대한 설명\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eskinparam\u003c/code\u003e 을 통해서 이 타입에 따라 스타일 적용 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e(기능이름)\u003c/code\u003e 괄호 안에 기능 이름을 입력\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eas xx\u003c/code\u003e 는 정의된 사용자를 뒤에서는 \u003ccode\u003exx\u003c/code\u003e 라는 키워드로 사용\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"기능-카테고리-정의\"\u003e기능 카테고리 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e기능을 카테고리화 하여 추상화\n\u003cul\u003e\n\u003cli\u003e전체 기능의 관계나 사용자 관점에서의 큰 그림을 잘 보기 위한 목적\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\n\n:서비스 사용자:  as user \u0026lt;\u0026lt; User \u0026gt;\u0026gt;\n:시스템 관리자:  as adm \u0026lt;\u0026lt; Admin \u0026gt;\u0026gt;\n\nrectangle \u0026quot;사용자 관리\u0026quot; {\n        (회원가입) as su\n        (로그인) as si\n}\n\nrectangle \u0026quot;식물 관리\u0026quot; {\n        (식물구경) as po\n        (식물구매) as pp\n        (장바구니) as bk\n        (식물업로드) as pu\n}\nrectangle \u0026quot;주문 관리\u0026quot; {\n        (결제) as pay\n        (결제내역 확인) as pl\n        (배송 조회) as delivery\n}\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-usecase-cat.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch4 id=\"문법-설명\"\u003e문법 설명\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003erectangle\u003c/code\u003e 은 박스를 그려주며, 안에 기능을 정의할 수 있도록 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"사용자와-기능간의-관계-정의\"\u003e사용자와 기능간의 관계 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e각 사용자 관점에서 어떤 기능을 사용할 수 있을지 관계 정의\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\n\n:서비스 사용자:  as user \u0026lt;\u0026lt; User \u0026gt;\u0026gt;\n:시스템 관리자:  as adm \u0026lt;\u0026lt; Admin \u0026gt;\u0026gt;\n\nrectangle \u0026quot;사용자 관리\u0026quot; {\n        (회원가입) as su\n        (로그인) as si\n}\n\nrectangle \u0026quot;식물 관리\u0026quot; {\n        (식물구경) as po\n        (식물구매) as pp\n        (장바구니) as bk\n        (식물업로드) as pu\n}\nrectangle \u0026quot;주문 관리\u0026quot; {\n        (결제) as pay\n        (결제내역 확인) as pl\n        (배송 조회) as delivery\n}\n\nuser --\u0026gt; su\nuser --\u0026gt; si\nuser --\u0026gt; pp\nuser --\u0026gt; po\nuser --\u0026gt; bk\nuser --\u0026gt; delivery\n\nadm --\u0026gt; pu\nadm --\u0026gt; pl\n\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-usecase-urel.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch4 id=\"문법-설명\"\u003e문법 설명\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e--\u0026gt;\u003c/code\u003e 실선 화살표로 관계 정의\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e-right-\u0026gt;\u003c/code\u003e, \u003ccode\u003e-left-\u0026gt;\u003c/code\u003e, \u003ccode\u003e-up-\u0026gt;\u003c/code\u003e, \u003ccode\u003e-down-\u0026gt;\u003c/code\u003e 등으로 방향을 나타낼 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"기능간의-관계-정의\"\u003e기능간의 관계 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e사용자 관점에서 기능을 사용할 때, 상호동작할 수 있는 기능간의 관계 정의\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\n\n:서비스 사용자:  as user \u0026lt;\u0026lt; User \u0026gt;\u0026gt;\n:시스템 관리자:  as adm \u0026lt;\u0026lt; Admin \u0026gt;\u0026gt;\n\nrectangle \u0026quot;사용자 관리\u0026quot; {\n        (회원가입) as su\n        (로그인) as si\n}\n\nrectangle \u0026quot;식물 관리\u0026quot; {\n        (식물구경) as po\n        (식물구매) as pp\n        (장바구니) as bk\n        (식물업로드) as pu\n}\nrectangle \u0026quot;주문 관리\u0026quot; {\n        (결제) as pay\n        (결제내역 확인) as pl\n        (배송 조회) as delivery\n}\n\nuser --\u0026gt; su\nuser --\u0026gt; si\nuser --\u0026gt; pp\nuser --\u0026gt; po\nuser --\u0026gt; bk\nuser --\u0026gt; delivery\n\nadm --\u0026gt; pu\nadm --\u0026gt; pl\n\nsu ..\u0026gt; si\nbk ..\u0026gt; pp\nsu ..\u0026gt; si\npp ..\u0026gt; pay: 결제 정보\nbk ..\u0026gt; pay: 식물 목록 및 결제 정보\npu ..\u0026gt; po\n\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-usecase-frel.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch4 id=\"문법-설명\"\u003e문법 설명\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e..\u0026gt;\u003c/code\u003e 실선 화살표로 관계 정의\n\u003cul\u003e\n\u003cli\u003e동일하게 방향을 적용할 수 있음.\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e..\u0026gt;: 설명\u003c/code\u003e 콜론 구분자를 통해서 추가적인 설명\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n"},{id:2,href:"https://hackartists.github.io/blog/%EB%AF%B8%EB%9F%AC%EB%A6%AC%EC%8A%A4%ED%8A%B8%EB%A5%BC-%EC%97%B0%EA%B2%B0%EC%83%81%ED%83%9C%EC%97%90-%EB%94%B0%EB%9D%BC-%EC%A0%95%EB%A0%AC-%EB%B0%8F-%EC%97%85%EB%8D%B0%EC%9D%B4%ED%8A%B8/",title:"미러리스트를 연결상태에 따라 정렬 및 업데이트",description:"This page explains how to update and rank a mirrorlist in Arch linux.",content:"\u003ch2 id=\"목적\"\u003e목적\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eArch 리눅스에서 미러리스트 업데이트\n\u003cul\u003e\n\u003cli\u003e업데이트시에 최신 미러리스트를 다운로드\u003c/li\u003e\n\u003cli\u003e다운로드된 미러리스트를 연결 상태에 따라 정렬\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"사전-요구필요사항\"\u003e사전 요구필요사항\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003epacman-contrib\u003c/code\u003e 설치\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003erankmirros\u003c/code\u003e 명령어 포함\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003epacman -S pacman-contrib\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch2 id=\"미러리스트-다운로드-및-정렬\"\u003e미러리스트 다운로드 및 정렬\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"https://archlinux.org/mirrorlist/\"  target=\"_blank\" rel=\"noopener\"\n    \u003ePacman mirrorlist generator\u003c/a\u003e 사용\n\u003cul\u003e\n\u003cli\u003e체크하고 싶은것들 체크후에 \u003ccode\u003eGenerate List\u003c/code\u003e 를 클릭\u003c/li\u003e\n\u003cli\u003e해당 링크를 사용하여 아래와 같이 수행\n\u003cul\u003e\n\u003cli\u003e예제에서 사용된 링크는 한국과 일본의 미러리스트를 대상으로 하는 링크\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003e\u003cspan class=\"nv\"\u003eServer\u003c/span\u003e \u003cspan class=\"o\"\u003e=\u003c/span\u003e http://mirror.premi.st/archlinux/\u003cspan class=\"nv\"\u003e$repo\u003c/span\u003e/os/\u003cspan class=\"nv\"\u003e$arch\u003c/span\u003e\n\u003cspan class=\"nv\"\u003eServer\u003c/span\u003e \u003cspan class=\"o\"\u003e=\u003c/span\u003e http://mirror.anigil.com/archlinux/\u003cspan class=\"nv\"\u003e$repo\u003c/span\u003e/os/\u003cspan class=\"nv\"\u003e$arch\u003c/span\u003e\n\u003cspan class=\"nv\"\u003eServer\u003c/span\u003e \u003cspan class=\"o\"\u003e=\u003c/span\u003e http://mirrors.cat.net/archlinux/\u003cspan class=\"nv\"\u003e$repo\u003c/span\u003e/os/\u003cspan class=\"nv\"\u003e$arch\u003c/span\u003e\n\u003cspan class=\"nv\"\u003eServer\u003c/span\u003e \u003cspan class=\"o\"\u003e=\u003c/span\u003e http://ftp.tsukuba.wide.ad.jp/Linux/archlinux/\u003cspan class=\"nv\"\u003e$repo\u003c/span\u003e/os/\u003cspan class=\"nv\"\u003e$arch\u003c/span\u003e\n\u003cspan class=\"nv\"\u003eServer\u003c/span\u003e \u003cspan class=\"o\"\u003e=\u003c/span\u003e http://ftp.jaist.ac.jp/pub/Linux/ArchLinux/\u003cspan class=\"nv\"\u003e$repo\u003c/span\u003e/os/\u003cspan class=\"nv\"\u003e$arch\u003c/span\u003e\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e"},{id:3,href:"https://hackartists.github.io/emacs/introduction/",title:"Introduction",description:"This page introduces Emacs.",content:"\u003cp\u003eEmacs를 사용하기 위해서 필요한 다양한 지식 및 기술 전달\u003c/p\u003e\n"},{id:4,href:"https://hackartists.github.io/infra/terminology/docker/",title:"Docker",description:"This page introduces docker.",content:"\u003ch2 id=\"호스트--host\"\u003e호스트(Host)\u003c/h2\u003e\n\u003cp\u003e도커 디먼을 수행하고 있는 운영체제 및 플랫폼\u003c/p\u003e\n\u003ch2 id=\"이미지--image\"\u003e이미지(Image)\u003c/h2\u003e\n\u003cp\u003e도커에서 관리되는 애플리케이션 템플릿\u003c/p\u003e\n\u003ch2 id=\"저장소--repository\"\u003e저장소(Repository)\u003c/h2\u003e\n\u003cp\u003e도커 이미지가 저장되는 저장소를 의미하며, 대부분은 \u003ccode\u003edomain/user-id/image-name\u003c/code\u003e 으로 구성됨\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edomain\u003c/code\u003e 이 기술되지 않으면 기본적으로 \u003ccode\u003ehub.docker.com\u003c/code\u003e 의 registry 도메인을 기본으로 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"컨테이너--container\"\u003e컨테이너(Container)\u003c/h2\u003e\n\u003cp\u003e인스턴스화(구동중인) 된 도커 이미지\u003c/p\u003e\n\u003ch2 id=\"볼륨--volume\"\u003e볼륨(Volume)\u003c/h2\u003e\n\u003cp\u003e컨테이너를 위한 저장 공간\u003c/p\u003e\n"},{id:5,href:"https://hackartists.github.io/infra/docker/introduction/",title:"개요",description:"This page introduces docker.",content:"\u003ch2 id=\"기본-개념\"\u003e\u003cspan class=\"org-todo done DONE\"\u003eDONE\u003c/span\u003e 기본 개념\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e각 애플리케이션마다 격리된 환경으로 관리\n\u003cul\u003e\n\u003cli\u003e서로 다른 애플리에키션간의 영향도를 최소화\u003c/li\u003e\n\u003cli\u003e하나의 컴퓨터 운영체제(Host OS)에 격리된 운영체제(Guest OS)를 생성\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e호스트 운영체제의 커널 공유를 통해 자원을 활용적으로 사용하기 위해 커널을 공유하여, CPU, RAM 등의 하드웨어 자원 공유\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/docker-basic-concept.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch2 id=\"도커-설치\"\u003e도커 설치\u003c/h2\u003e\n\u003cp\u003e\u003ca href=\"https://docs.docker.com/get-docker/\"\u003ehttps://docs.docker.com/get-docker/\u003c/a\u003e 를 참고하여 다양한 운영체제에서 설치할 수 있음.\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eMac OS\u003c/li\u003e\n\u003cli\u003eWindows\u003c/li\u003e\n\u003cli\u003eLinux\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"arch-linux-에서-도커-설치\"\u003eArch Linux 에서 도커 설치\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eyay\u003c/code\u003e, \u003ccode\u003epacman\u003c/code\u003e 등을 이용하여 설치 할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003epacman -S docker\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch2 id=\"도커-실행\"\u003e도커 실행\u003c/h2\u003e\n\u003ch3 id=\"도커-디먼-실행\"\u003e도커 디먼 실행\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003esystemctl\u003c/code\u003e 명령어를 사용하여 도커 디먼을 실행\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003esystemctl start docker\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch3 id=\"도커-디먼-실행-확인\"\u003e도커 디먼 실행 확인\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003esystemctl\u003c/code\u003e 를 이용하여 도커 디먼 실행 여부를 확인할 수 있음.\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003esystemctl\u003c/code\u003e 에서 상태(status)가 \u003ccode\u003eactive\u003c/code\u003e 로 나오면, 정상적으로 실행됨.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003esystemctl status docker\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003cpre\u003e\u003ccode class=\"language-nil\" data-lang=\"nil\"\u003e...\nActive: active (running) ...\n...\n\u003c/code\u003e\u003c/pre\u003e\u003ch3 id=\"도커-명령어\"\u003e도커 명령어\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker\u003c/code\u003e 명령어를 실행하여, 하위 명령어 리스트 보기.\n\u003cul\u003e\n\u003cli\u003e반드시 도커 디먼이 실행되고, 있어야지 볼 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e#+end_src\u003c/p\u003e\n"},{id:6,href:"https://hackartists.github.io/design/uml/sequence/",title:"시퀀스(Sequence) 다이어그램",description:"This page explains how to draw sequence diagram with plantuml.",content:"\u003ch2 id=\"시퀀스-다이어그램이란\"\u003e시퀀스 다이어그램이란?\u003c/h2\u003e\n\u003ch3 id=\"정의-및-목적\"\u003e정의 및 목적\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e시간의 흐름에 따른 오브젝트들간의 상호동작(interaction)을 표현\n\u003cul\u003e\n\u003cli\u003e시나리오에 연관된 오브젝트들을 표현\u003c/li\u003e\n\u003cli\u003e각 오브젝트들간의 주고받는 메시지 표현\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e이벤트 다이어그램(event diagrams) 또는 이벤트 시나리오(event scenarios)로 불리기도 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"시퀀스-다이어그램\"\u003e시퀀스 다이어그램\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"/design/uml/usecase-diagram/\" \u003e유즈케이스 다이어그램\u003c/a\u003e에서 작성한 \u003ccode\u003e식물구매\u003c/code\u003e 시나리오\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-sequence-top.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch2 id=\"시퀀스-다이어그램-그리기\"\u003e시퀀스 다이어그램 그리기\u003c/h2\u003e\n\u003ch3 id=\"카테고리별-참여자-정의\"\u003e카테고리별 참여자 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e해당 시나리오 참여하는 사용자 및 서비스를 정의\n\u003cul\u003e\n\u003cli\u003e시나리오를 그리면서 혼동을 피하기 위해서 참여자를 명확히 정의\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\n\nactor \u0026quot;서비스 사용자\u0026quot; as u\nbox \u0026quot;식물 쇼핑몰 서비스\u0026quot;\n        participant \u0026quot;식물앱\u0026quot; as app\n        control \u0026quot;인증 서버\u0026quot; as auth\n        participant \u0026quot;API 서버\u0026quot; as api\n        database \u0026quot;사용자 DB\u0026quot; as adb\n        database \u0026quot;식물 DB\u0026quot; as db\nend box\n\nbox \u0026quot;외부 서비스\u0026quot;\n        participant \u0026quot;페이먼트 게이트웨이(PG)\u0026quot; as pg\nend box\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-sequence-participants.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch4 id=\"문법-설명\"\u003e문법 설명\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e참여자 키워드는 \u003ccode\u003eactor\u003c/code\u003e, \u003ccode\u003eparticipant\u003c/code\u003e, \u003ccode\u003econtrol\u003c/code\u003e 등 다양한 키워드가 있음.\n\u003cul\u003e\n\u003cli\u003e상세한 정보는\u003ca class=\"link\" href=\"https://plantuml-documentation.readthedocs.io/en/latest/diagrams/sequence.html#participants\"  target=\"_blank\" rel=\"noopener\"\n    \u003ePlant UML 참여자 설명\u003c/a\u003e에서 확인\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eas xx\u003c/code\u003e 는 시퀀스 다이어그램을 그릴때 사용할 이름(\u003ccode\u003exx\u003c/code\u003e)을 정의\u003c/li\u003e\n\u003cli\u003e인터넷 서비스 설계측면에서는 주로 \u003ccode\u003eactor\u003c/code\u003e, \u003ccode\u003eparticipant\u003c/code\u003e, \u003ccode\u003edatabase\u003c/code\u003e 수준을 사용\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ebox\u003c/code\u003e 는 시나리오 측면에서 각 참여자들을 쉽게 구분하기 위해서 사용\n\u003cul\u003e\n\u003cli\u003e외부 컴포넌트 및 참여자의 특징을 구분\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"사용자-시나리오-정의\"\u003e사용자 시나리오 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e사용자가 수행하는 행위를 중심으로 시나리오 작성\n\u003cul\u003e\n\u003cli\u003e사용자 관점에서의 행위와 정보에 중점을 맞춤.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e본 시나리오에서는 사용자와 웹/앱 간의 시나리오 작성\n\u003cul\u003e\n\u003cli\u003e개발자와 기획자 간의 협의를 위해서 사용될 수 있음.\u003c/li\u003e\n\u003cli\u003e요구되는 정보에 대한 상세화가 될수록 좋음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\nskinparam sequence {\n        groupbodybackgroundcolor transparent\n}\nactor \u0026quot;서비스 사용자\u0026quot; as u\nbox \u0026quot;식물 쇼핑몰 서비스\u0026quot;\n        participant \u0026quot;식물앱\u0026quot; as app\n        control \u0026quot;인증 서버\u0026quot; as auth\n        participant \u0026quot;API 서버\u0026quot; as api\n        database \u0026quot;사용자 DB\u0026quot; as adb\n        database \u0026quot;식물 DB\u0026quot; as db\nend box\n\nbox \u0026quot;외부 서비스\u0026quot;\n        participant \u0026quot;페이먼트 게이트웨이(PG)\u0026quot; as pg\nend box\n\nu -\u0026gt; app+: 식물검색\nreturn 식물목록 페이지\nu -\u0026gt; app+: 식물선택\nreturn 식물 상세페이지\nu -\u0026gt; app: 식물 구매\nactivate app\n        app -\u0026gt; u: 로그인 페이지\n        u -\u0026gt; app: 로그인 정보\n        alt 인증성공\n                app -\u0026gt; u: 인증완료 및 결제페이지\n                u -\u0026gt; app: 결제\n                app -\u0026gt; u: 결제 결과 페이지\n        else 인증실패\n                app -\u0026gt; u: 인증에러\n        end\ndeactivate app\n\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-sequence-userscene.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch4 id=\"문법-설명\"\u003e문법 설명\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ea -\u0026gt; b: {{message}}\u003c/code\u003e 는 \u003ccode\u003ea\u003c/code\u003e 가 \u003ccode\u003eb\u003c/code\u003e 에게 \u003ccode\u003e{{message}}\u003c/code\u003e 를 준다라는 의미\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e-\u0026gt;\u003c/code\u003e 실선으로 연결 해주며, \u003ccode\u003e--\u0026gt;\u003c/code\u003e 사용시 점선으로 표시됨.\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ea -\u0026gt; b+: ..\u003c/code\u003e 를 사용시에 \u003ccode\u003eb\u003c/code\u003e 를 활성화 시킨다는 의미\n\u003cul\u003e\n\u003cli\u003e활성화란 시퀀스 다이어그램에서 하얀선을 표시해서 세션이 유지됨을 표시\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ereturn\u003c/code\u003e 과 쌍으로 사용되어야 하며, 가장 가까운것을 기준으로 세션이 비활성화 됨.\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ereturn\u003c/code\u003e 점선 화살표를 생성\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eactivate\u003c/code\u003e, \u003ccode\u003edeactivate\u003c/code\u003e 도 \u003ccode\u003e+\u003c/code\u003e 와 동일하게 세션 활성화를 의미\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eactivate\u003c/code\u003e, \u003ccode\u003edeactivate\u003c/code\u003e 처리가 끝난 다음에 명시적으로 비활성화\u003c/li\u003e\n\u003cli\u003e가장 근접한 순으로 리턴하는 경우가 아닐 때 사용\u003c/li\u003e\n\u003cli\u003e여러번의 \u003ccode\u003edeactivate\u003c/code\u003e 가 가능하므로, 리턴이 명시적이지 않을때 사용 가능.\u003c/li\u003e\n\u003cli\u003e세션 활성화 구간을 명확하게 하고 싶을 때 사용\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ealt/else/end\u003c/code\u003e 를 통해서 특정 케이스 대한 시나리오 작성\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eelse\u003c/code\u003e 를 여러개 입력하여 상황을 추가 할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"서비스간-시나리오-정의\"\u003e서비스간 시나리오 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e서비스 간에 동작하는 시나리오에 대해서 작성\n\u003cul\u003e\n\u003cli\u003e개발자들간의 협의를 위해서 주로 사용할 수 있음.\u003c/li\u003e\n\u003cli\u003e인터페이스를 중심으로 작성하면, 도움이 될 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\nskinparam sequence {\n        groupbodybackgroundcolor transparent\n}\nactor \u0026quot;서비스 사용자\u0026quot; as u\nbox \u0026quot;식물 쇼핑몰 서비스\u0026quot;\n        participant \u0026quot;식물앱\u0026quot; as app\n        control \u0026quot;인증 서버\u0026quot; as auth\n        participant \u0026quot;API 서버\u0026quot; as api\n        database \u0026quot;사용자 DB\u0026quot; as adb\n        database \u0026quot;식물 DB\u0026quot; as db\nend box\n\nbox \u0026quot;외부 서비스\u0026quot;\n        participant \u0026quot;페이먼트 게이트웨이(PG)\u0026quot; as pg\nend box\n\nu -\u0026gt; app+: 식물검색\napp -\u0026gt; api+: 검색정보\nreturn 식물목록\nreturn 식물목록 페이지\nu -\u0026gt; app+: 식물선택\napp -\u0026gt; api+: 식물아이디\nreturn 식물상세정보\nreturn 식물 상세페이지\nu -\u0026gt; app: 식물 구매\nactivate app\n        app -\u0026gt; u: 로그인 페이지\n        u -\u0026gt; app: 로그인 정보\n        app -\u0026gt; auth: 사용자 이름, 비밀번호\n        activate auth\n                auth -\u0026gt; auth: 사용자 검증\n\n                alt 인증성공\n                        auth -\u0026gt; app: 인증토큰\n                        app -\u0026gt; u: 인증완료 및 결제페이지\n                        u -\u0026gt; app: 결제\n                        app -\u0026gt; u: 결제 결과 페이지\n                else 인증실패\n                        auth -\u0026gt; app: 에러\n                        deactivate auth\n                        app -\u0026gt; u: 인증에러\n                end\n        deactivate auth\ndeactivate app\n\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-sequence-service.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch3 id=\"서비스간-상세시나리오-정의\"\u003e서비스간 상세시나리오 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e데이터베이스 및 외부서비스와의 상호동작에 대해서 작성\n\u003cul\u003e\n\u003cli\u003e본 단계는 인터넷 서비스 설계에서는 작성하지 않아도 설계상에 큰 문제는 없음.\u003c/li\u003e\n\u003cli\u003e설계를 최소화하고자 하는 경우에는 작성하지 않을 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\nskinparam sequence {\n        groupbodybackgroundcolor transparent\n}\nactor \u0026quot;서비스 사용자\u0026quot; as u\nbox \u0026quot;식물 쇼핑몰 서비스\u0026quot;\n        participant \u0026quot;식물앱\u0026quot; as app\n        control \u0026quot;인증 서버\u0026quot; as auth\n        participant \u0026quot;API 서버\u0026quot; as api\n        database \u0026quot;사용자 DB\u0026quot; as adb\n        database \u0026quot;식물 DB\u0026quot; as db\nend box\n\nbox \u0026quot;외부 서비스\u0026quot;\n        participant \u0026quot;페이먼트 게이트웨이(PG)\u0026quot; as pg\nend box\n\nu -\u0026gt; app+: 식물검색\napp -\u0026gt; api+: 검색정보\napi -\u0026gt; db+: 식물검색 쿼리\nreturn 검색결과\nreturn 식물목록\nreturn 식물목록 페이지\nu -\u0026gt; app+: 식물선택\napp -\u0026gt; api+: 식물아이디\napi -\u0026gt; db+: 식물아이디 조회\nreturn 식물상세정보\nreturn 식물상세정보\nreturn 식물 상세페이지\nu -\u0026gt; app: 식물 구매\nactivate app\n        app -\u0026gt; u: 로그인 페이지\n        u -\u0026gt; app: 로그인 정보\n        app -\u0026gt; auth: 사용자 이름, 비밀번호\n        activate auth\n                auth -\u0026gt; adb+: 사용자이름, 비밀번호\n                return 사용자 정보\n                auth -\u0026gt; auth: 사용자 검증\n\n                alt 인증성공\n                        auth -\u0026gt; app: 인증토큰\n                        app -\u0026gt; u: 인증완료 및 결제페이지\n                        u -\u0026gt; app: 결제\n                        app -\u0026gt; pg: 상품결제정보, 사용자정보\n                        activate pg\n                                pg --\u0026gt; u: 결제페이지\n                                u --\u0026gt; pg: 결제정보\n                                alt 결제성공\n                                        pg -\u0026gt; app: 결제키\n                                        app -\u0026gt; api+: 결제키정보\n                                        api -\u0026gt; pg: 결제키\n                                        pg -\u0026gt; api: 결제정보\n                                        return 완료\n                                else 결제실패\n                                        pg -\u0026gt; app: 결제에러\n                                end\n                        deactivate pg\n                        app -\u0026gt; u: 결제 결과 페이지\n                else 인증실패\n                        auth -\u0026gt; app: 에러\n                        deactivate auth\n                        app -\u0026gt; u: 인증에러\n                end\n        deactivate auth\ndeactivate app\n\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-sequence-db.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch3 id=\"스타일-적용-및-가독성-향상\"\u003e스타일 적용 및 가독성 향상\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e박스와 참여자간의 간격 조정을 위해서 패딩을 스타일 적용\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eboxpadding\u003c/code\u003e, \u003ccode\u003eparticipantpadding\u003c/code\u003e 적용\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e== xx ==\u003c/code\u003e 를 통해서 분리자를 추가할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003e@startuml\nskinparam backgroundcolor transparent\nskinparam boxpadding 10\nskinparam sequence {\n        participantpadding 20\n        groupbodybackgroundcolor transparent\n}\nactor \u0026quot;서비스 사용자\u0026quot; as u\nbox \u0026quot;식물 쇼핑몰 서비스\u0026quot;\n        participant \u0026quot;식물앱\u0026quot; as app\n        control \u0026quot;인증 서버\u0026quot; as auth\n        participant \u0026quot;API 서버\u0026quot; as api\n        database \u0026quot;사용자 DB\u0026quot; as adb\n        database \u0026quot;식물 DB\u0026quot; as db\nend box\n\nbox \u0026quot;외부 서비스\u0026quot;\n        participant \u0026quot;페이먼트 게이트웨이(PG)\u0026quot; as pg\nend box\n\n== 비회원 및 회원 앱 사용 ==\nu -\u0026gt; app+: 식물검색\napp -\u0026gt; api+: 검색정보\napi -\u0026gt; db+: 식물검색 쿼리\nreturn 검색결과\nreturn 식물목록\nreturn 식물목록 페이지\nu -\u0026gt; app+: 식물선택\napp -\u0026gt; api+: 식물아이디\napi -\u0026gt; db+: 식물아이디 조회\nreturn 식물상세정보\nreturn 식물상세정보\nreturn 식물 상세페이지\n\n== 회원전용 식물 구매 ==\nu -\u0026gt; app: 식물 구매\nactivate app\n        app -\u0026gt; u: 로그인 페이지\n        u -\u0026gt; app: 로그인 정보\n        app -\u0026gt; auth: 사용자 이름, 비밀번호\n        activate auth\n                auth -\u0026gt; adb+: 사용자이름, 비밀번호\n                return 사용자 정보\n                auth -\u0026gt; auth: 사용자 검증\n\n                alt 인증성공\n                        auth -\u0026gt; app: 인증토큰\n                        app -\u0026gt; u: 인증완료 및 결제페이지\n                        u -\u0026gt; app: 결제\n                        app -\u0026gt; pg: 상품결제정보, 사용자정보\n                        activate pg\n                                pg --\u0026gt; u: 결제페이지\n                                u --\u0026gt; pg: 결제정보\n                                alt 결제성공\n                                        pg -\u0026gt; app: 결제키\n                                        app -\u0026gt; api+: 결제키정보\n                                        api -\u0026gt; pg: 결제키\n                                        pg -\u0026gt; api: 결제정보\n                                        return 완료\n                                else 결제실패\n                                        pg -\u0026gt; app: 결제에러\n                                end\n                        deactivate pg\n                        app -\u0026gt; u: 결제 결과 페이지\n                else 인증실패\n                        auth -\u0026gt; app: 에러\n                        deactivate auth\n                        app -\u0026gt; u: 인증에러\n                end\n        deactivate auth\ndeactivate app\n\n@enduml\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-sequence-style.png\"/\u003e \n\u003c/figure\u003e\n\n"},{id:7,href:"https://hackartists.github.io/emacs/macos/input-method/",title:"Mac OS 키보드 레이아웃 인코딩",description:"This page explains how shortcut for switching keyboard layout can be set as same between Mac OS and Emacs.",content:"\u003ch2 id=\"mac-os-에서의-키보드-단축키-이슈\"\u003eMac OS 에서의 키보드 단축키 이슈\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eShift+SPC\u003c/code\u003e 를 Mac OS와 Emacs의 키보드 한/영 전환 단축키로 사용하는 경우\n\u003cul\u003e\n\u003cli\u003eMac OS 에서 단축키를 먼저 인터셉트하기 때문에, Emacs의 \u003ccode\u003etoggle-input-method\u003c/code\u003e 가 호출되지 않고 OS 레벨의 레이아웃이 변함.\u003c/li\u003e\n\u003cli\u003e한글 입력 자체는 되지만, \u003ccode\u003eM-x\u003c/code\u003e 를 입력했을 때, \u003ccode\u003eM-ㅌ\u003c/code\u003e 등으로 나오면서 명령어가 정상적으로 동작 안함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"해결을-위한-기본-개념\"\u003e해결을 위한 기본 개념\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eMac OS 와 Emacs 의 한영 전환을 다르게 설정하면 됨.\n\u003cul\u003e\n\u003cli\u003eMac OS 의 한/영 전환을 \u003ccode\u003eCMD+SPC\u003c/code\u003e 로 설정\u003c/li\u003e\n\u003cli\u003eEmacs 의 \u003ccode\u003etoggle-input-method\u003c/code\u003e 를 다르게 설정\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003eMac OS 와 Emacs 에서 서로 다른 단축키를 사용해야 하기 때문에 헷갈림\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"동일한-키를-이용하여-한영-전환-설정\"\u003e동일한 키를 이용하여 한영 전환 설정\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eMac OS에서는 \u003ccode\u003e한/영 전환\u003c/code\u003e 을 \u003ccode\u003eCMD+SPC\u003c/code\u003e 로 설정하고, Emacs 에서는 \u003ccode\u003eS-SPC\u003c/code\u003e 로 설정\u003c/li\u003e\n\u003cli\u003e활성화(frontmost)된 애플리케이션이 \u003ccode\u003eEmacs\u003c/code\u003e 가 아닐 때는 \u003ccode\u003eShift+SPC\u003c/code\u003e 가 \u003ccode\u003eCMD+SPC\u003c/code\u003e 인 것처럼 동작하도록 설정\n\u003cul\u003e\n\u003cli\u003e해당 설정을 하기 위해서 \u003ccode\u003ekarabiner elements\u003c/code\u003e 를 통해서 수행할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"karabiner-elements-설치\"\u003eKarabiner elements 설치\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ebrew\u003c/code\u003e 를 통해서 설치 할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003ebrew cask install karabiner-elements\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch3 id=\"karabiner-elements-설정\"\u003eKarabiner elements 설정\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e~/.config/karabiner/assets/complex_modifications/emacs.json\u003c/code\u003e 에 설정\n\u003cul\u003e\n\u003cli\u003e상세 설정 방법은 \u003ca class=\"link\" href=\"https://karabiner-elements.pqrs.org/docs/json/complex-modifications-manipulator-definition/\"  target=\"_blank\" rel=\"noopener\"\n    \u003eKarabiner-Elements 문법 사이트\u003c/a\u003e에서 확인 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-json\" data-lang=\"json\"\u003e\u003cspan class=\"p\"\u003e{\u003c/span\u003e\n    \u003cspan class=\"nt\"\u003e\u0026#34;title\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"s2\"\u003e\u0026#34;shift_spacebar to command_spacebar unless Emacs\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e,\u003c/span\u003e\n    \u003cspan class=\"nt\"\u003e\u0026#34;maintainers\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n        \u003cspan class=\"s2\"\u003e\u0026#34;hackaritst\u0026#34;\u003c/span\u003e\n    \u003cspan class=\"p\"\u003e],\u003c/span\u003e\n    \u003cspan class=\"nt\"\u003e\u0026#34;rules\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n        \u003cspan class=\"p\"\u003e{\u003c/span\u003e\n            \u003cspan class=\"nt\"\u003e\u0026#34;description\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"s2\"\u003e\u0026#34;shift_spacebar to command_spacebar unless Emacs\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e,\u003c/span\u003e\n            \u003cspan class=\"nt\"\u003e\u0026#34;manipulators\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n                \u003cspan class=\"p\"\u003e{\u003c/span\u003e\n                    \u003cspan class=\"nt\"\u003e\u0026#34;type\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"s2\"\u003e\u0026#34;basic\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e,\u003c/span\u003e\n                    \u003cspan class=\"nt\"\u003e\u0026#34;from\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e{\u003c/span\u003e\n                        \u003cspan class=\"nt\"\u003e\u0026#34;key_code\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"s2\"\u003e\u0026#34;spacebar\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e,\u003c/span\u003e\n                        \u003cspan class=\"nt\"\u003e\u0026#34;modifiers\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e{\u003c/span\u003e\n                            \u003cspan class=\"nt\"\u003e\u0026#34;mandatory\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n                                \u003cspan class=\"s2\"\u003e\u0026#34;shift\u0026#34;\u003c/span\u003e\n                            \u003cspan class=\"p\"\u003e]\u003c/span\u003e\n                        \u003cspan class=\"p\"\u003e}\u003c/span\u003e\n                    \u003cspan class=\"p\"\u003e},\u003c/span\u003e\n                    \u003cspan class=\"nt\"\u003e\u0026#34;to\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n                        \u003cspan class=\"p\"\u003e{\u003c/span\u003e\n                            \u003cspan class=\"nt\"\u003e\u0026#34;key_code\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"s2\"\u003e\u0026#34;spacebar\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e,\u003c/span\u003e\n                            \u003cspan class=\"nt\"\u003e\u0026#34;modifiers\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n                                \u003cspan class=\"s2\"\u003e\u0026#34;left_command\u0026#34;\u003c/span\u003e\n                            \u003cspan class=\"p\"\u003e]\u003c/span\u003e\n                        \u003cspan class=\"p\"\u003e}\u003c/span\u003e\n                    \u003cspan class=\"p\"\u003e],\u003c/span\u003e\n                    \u003cspan class=\"nt\"\u003e\u0026#34;conditions\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n                        \u003cspan class=\"p\"\u003e{\u003c/span\u003e\n                            \u003cspan class=\"nt\"\u003e\u0026#34;type\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"s2\"\u003e\u0026#34;frontmost_application_unless\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e,\u003c/span\u003e\n                            \u003cspan class=\"nt\"\u003e\u0026#34;bundle_identifiers\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e:\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\n                                \u003cspan class=\"s2\"\u003e\u0026#34;^org\\\\.gnu\\\\.Emacs$\u0026#34;\u003c/span\u003e\n                            \u003cspan class=\"p\"\u003e]\u003c/span\u003e\n                        \u003cspan class=\"p\"\u003e}\u003c/span\u003e\n                    \u003cspan class=\"p\"\u003e]\u003c/span\u003e\n                \u003cspan class=\"p\"\u003e}\u003c/span\u003e\n            \u003cspan class=\"p\"\u003e]\u003c/span\u003e\n        \u003cspan class=\"p\"\u003e}\u003c/span\u003e\n    \u003cspan class=\"p\"\u003e]\u003c/span\u003e\n\u003cspan class=\"p\"\u003e}\u003c/span\u003e\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e"},{id:8,href:"https://hackartists.github.io/design/introduction/",title:"Design",description:"This page introduces design for service development.",content:"\u003cp\u003e개발에 앞서 설계를 하는 단계\u003c/p\u003e\n\u003ch2 id=\"주요-역할\"\u003e주요 역할\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e요구사항 및 사용자 시나리오 도출\u003c/li\u003e\n\u003cli\u003e기능 및 배포 아키텍처 설계\u003c/li\u003e\n\u003cli\u003e사용자 인터페이스 설계\u003c/li\u003e\n\u003cli\u003e그 외 프로젝트 관리 도구 및 방법 설정\u003c/li\u003e\n\u003cli\u003e개발을 위한 기술 조사\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"주요-스킬\"\u003e주요 스킬\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e구조화 및 추상화 능력\u003c/li\u003e\n\u003cli\u003eUI/UX 디자인 능력\u003c/li\u003e\n\u003cli\u003e리스크 분석 능력\u003c/li\u003e\n\u003cli\u003e프로세스 수립 능력\u003c/li\u003e\n\u003cli\u003e신기술에 대한 학습 능력\u003c/li\u003e\n\u003cli\u003e\u003c/li\u003e\n\u003c/ul\u003e\n"},{id:9,href:"https://hackartists.github.io/infra/docker/docker-basic/",title:"컨테이너 관리",description:"This page explains how you can manage docker containers.",content:"\u003ch2 id=\"컨테이너-생성\"\u003e컨테이너 생성\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eCentOS 이미지를 이용하여 도커 컨테이너 생성\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e-it\u003c/code\u003e 옵션은 컨테이너의 터미널(TTY)와 입력장치(STDIN)를 연결(attach)하면서 실행\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e--name\u003c/code\u003e 옵션은 컨테이너 이름을 특정 이름으로 지정\n\u003cul\u003e\n\u003cli\u003e이름이 지정되어 있으면 해당 컨테이너를 관리할 때, 지정한 이름으로 관리 할 수 있음.\u003c/li\u003e\n\u003cli\u003e이름이 없으면, 무작위로 이름이 만들어지며, 해당 컨테이너를 관리할 때, 무작위 이름 또는 컨테이너 해시의 앞에 3-4자리 정도를 이용할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker run --name centos -it centos\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003cul\u003e\n\u003cli\u003e접속된 도커 터미널을 종료하는 방법\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eCtrl-p Ctrl-q\u003c/code\u003e 단축키를 통해서 컨테이너는 종료하지 않고 종료 가능\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eexit\u003c/code\u003e 으로 종료하면, 컨테이너도 종료되며, =docker start centos=로 시작 가능\n\u003cul\u003e\n\u003cli\u003e재시작된 컨테이너에 접속 하는 방법은 다음장 참고\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"컨테이너에-연결\"\u003e컨테이너에 연결\u003c/h2\u003e\n\u003ch3 id=\"컨테이너-상태-확인\"\u003e\u003cspan class=\"org-todo done DONE\"\u003eDONE\u003c/span\u003e 컨테이너 상태 확인\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker ps\u003c/code\u003e 를 통해서, 실행되고 있는 컨테이너 조회\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003edocker ps -a\u003c/code\u003e 를 통해서, 생성된 모든 컨테이너 조회\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003edocker ps -a -f name=centos\u003c/code\u003e 를 사용하여, 컨테이너 이름이 \u003ccode\u003ecentos\u003c/code\u003e 인 정보만 조회\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003efilter\u003c/code\u003e 에 대한 상세한 설명은 \u003ca class=\"link\" href=\"https://docs.docker.com/engine/reference/commandline/ps/#filtering\"  target=\"_blank\" rel=\"noopener\"\n    \u003e도커 필터 설명\u003c/a\u003e에서 확인 가능\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003edocker ps -a | grep centos\u003c/code\u003e 도 비슷한 결과를 얻을 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003edocker ps --format \u0026quot;table {{.Names}}\\t{{.Status}}\\t{{.Ports}}\u0026quot;\u003c/code\u003e 를 사용하여, 최소의 정보만 출력 가능\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eformat\u003c/code\u003e 에 들어가는 상세한 내용은 \u003ca class=\"link\" href=\"https://docs.docker.com/engine/reference/commandline/ps/#formatting\"  target=\"_blank\" rel=\"noopener\"\n    \u003e도커 포맷 설명\u003c/a\u003e에서 확인 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"컨테이너에-접속\"\u003e컨테이너에 접속\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eexec\u003c/code\u003e 하위 명령어를 이용하여 컨테이너에 접속할 수 있음.\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e-it\u003c/code\u003e 옵션을 반드시 붙여야하며, 실행되고 있는 컨테이너에 접속하는 것이 아니라, 명령어를 수행하는 \u003ccode\u003ebash\u003c/code\u003e 명령어를 수행하는 것임.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker \u003cspan class=\"nb\"\u003eexec\u003c/span\u003e -it centos bash\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eattach\u003c/code\u003e 를 통해서 실행되고 있는 컨테이너에 접속할 수 있음.\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eCtrl-p Ctrl-q\u003c/code\u003e 단축키로 종료\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"도커-허브--docker-hub\"\u003e\u003cspan class=\"org-todo done DONE\"\u003eDONE\u003c/span\u003e 도커 허브(Docker hub)\u003c/h2\u003e\n\u003ch3 id=\"도커-허브란\"\u003e도커 허브란?\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e도커 이미지 검색 포털\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003esearch\u003c/code\u003e 하위 명령어를 통해서 이미지 검색 가능\n\u003cul\u003e\n\u003cli\u003e검색된 이미지로 컨테이너 생성이 가능함\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker search ubuntu\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003eNAME\u003c/th\u003e\n\u003cth\u003eDESCRIPTION\u003c/th\u003e\n\u003cth\u003eSTARS\u003c/th\u003e\n\u003cth\u003eOFFICIAL\u003c/th\u003e\n\u003cth\u003eAUTOMATED\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003eubuntu\u003c/td\u003e\n\u003ctd\u003eUbuntu is a Debian-based Linux operating sys…\u003c/td\u003e\n\u003ctd\u003e11806\u003c/td\u003e\n\u003ctd\u003e[OK]\u003c/td\u003e\n\u003ctd\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003edorowu/ubuntu-desktop-lxde-vnc\u003c/td\u003e\n\u003ctd\u003eDocker image to provide HTML5 VNC interface\u003c/td\u003e\n\u003ctd\u003e…\u003c/td\u003e\n\u003ctd\u003e497\u003c/td\u003e\n\u003ctd\u003e[OK]\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch3 id=\"도커-허브-포탈-사용\"\u003e도커 허브 포탈 사용\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca class=\"link\" href=\"https://hub.docker.com/\"  target=\"_blank\" rel=\"noopener\"\n    \u003e도커 허브\u003c/a\u003e\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e도커 허브는 웹 UI 를 기반으로 이미지 검색이 가능\n\u003cul\u003e\n\u003cli\u003e검색된 이미지 정보에서 \u003ccode\u003etags\u003c/code\u003e 탭을 통해서 해당 이미지의 태그를 확인 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/2021-02-09_23-13-27_screenshot.png\"/\u003e \n\u003c/figure\u003e\n\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"도커-이미지-및-태그-사용\"\u003e도커 이미지 및 태그 사용\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e도커 허브에서 이미지 검색\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003etags\u003c/code\u003e 탭에서 이미지의 태그 검색\u003c/li\u003e\n\u003cli\u003e도커 컨테이너 생성할 때, \u003ccode\u003e{image repository}:{tag}\u003c/code\u003e 형태로 이미지를 기술하여 사용 가능\n\u003cul\u003e\n\u003cli\u003e아래의 명령어는 우분투 \u003ccode\u003e20.04\u003c/code\u003e 태그 버전을 실행하는 방법임.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker run -it --name ubuntu ubuntu:20.04\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e"},{id:10,href:"https://hackartists.github.io/design/uml/activity/",title:"액티비티(Activity) 다이어그램",description:"This page explains how to draw activity diagram with plantuml.",content:"\u003ch2 id=\"정의-및-목적\"\u003e정의 및 목적\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e액티비티 다이어그램은 액티비티(activity) 및 액션(action)을 표현\n\u003cul\u003e\n\u003cli\u003e반복, 조건, 병렬 등을 표현\u003c/li\u003e\n\u003cli\u003e전체적의 제어 흐름을 보여주는 것이 주요 목적\n\u003cul\u003e\n\u003cli\u003e필요에 따라 데이터의 흐름도 보여줄 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"액티비티-다이어그램-주요-표현\"\u003e액티비티 다이어그램 주요 표현\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e검정색 원은 시작점\u003c/li\u003e\n\u003cli\u003e이중선이 있는 검정색 원은 종료점\u003c/li\u003e\n\u003cli\u003e타원은 액션(action), 다이아몬드 또는 육각형은 결정(decision)을 표현\u003c/li\u003e\n\u003cli\u003e바(bar)는 병렬 액티비티의 시작(split) 및 종료(join)를 표현\u003c/li\u003e\n\u003cli\u003e컬럼(swimlane)은 각 각 컴포넌트를 의미\n\u003cul\u003e\n\u003cli\u003e추상화된 레벨에서 전체 컴포넌트 간의 액션의 흐름을 보기 용이함.\u003c/li\u003e\n\u003cli\u003e복잡한 서비스의 경우에는 액션의 흐름을 미리 파악할 필요가 있음.\u003c/li\u003e\n\u003cli\u003e개발자들간의 잘못된 소통을 사전에 방지해줄 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-activity-reps.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch2 id=\"액티비티-다이어그램-그리기\"\u003e액티비티 다이어그램 그리기\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003ePlant UML 을 이용하여 아래와 같은 절차를 통해서 그릴 수 있음.\n\u003cul\u003e\n\u003cli\u003e본 섹션에서는 서비스 설계에 필요한 최소화를 설명하며 \u003ca class=\"link\" href=\"https://plantuml.com/ko/activity-diagram-beta\"  target=\"_blank\" rel=\"noopener\"\n    \u003ePlant UML 설명\u003c/a\u003e 을 참고\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e메인 컴포넌트에서 확장해나가는 방식으로 그릴 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"관련-컴포넌트-정의\"\u003e관련 컴포넌트 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e다수 컴포넌트가 포함된 엑티비티를 그릴 경우에만 해당됨.\n\u003cul\u003e\n\u003cli\u003e엑티비티 다이어그램은 하나의 컴포넌트에 대한 상세 흐름을 정의하는 경우가 다수이므로 본 단계를 수행하지 않을 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003eskinparam backgroundcolor transparent\n\n|컴포넌트1|\n|메인컴포넌트|\n|컴포넌트2|\n\n|메인컴포넌트|\nstart\nstop\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-activity-def-comps.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch3 id=\"메인-컴포넌트의-결정-로직-정의\"\u003e메인 컴포넌트의 결정 로직 정의\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e메인 컴포넌트의 로직을 중심으로 프로세스를 크게 그림.\n\u003cul\u003e\n\u003cli\u003e다른 컴포넌트와 연동은 표시하는 정도 수준\u003c/li\u003e\n\u003cli\u003e결정 및 병렬 로직등은 상세하게 보여야 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003eskinparam backgroundcolor transparent\n\n|컴포넌트1|\n|메인컴포넌트|\n|컴포넌트2|\n\n|메인컴포넌트|\nstart\n\nif (조건을 만족하는지?) then (예)\n        :위의 조건을 만족하는경우\n        병렬 프로세스를 시작;\n        fork\n                :컴포넌트1에 요청;\n        fork again\n                :컴포넌트2에 요청;\n        end fork\nelse (아니요)\n        :틀렸을때 수행할 프로세스;\nendif\n\nstop\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-activity-main-logic.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch3 id=\"메인-컴포넌트의-로직-상세화\"\u003e메인 컴포넌트의 로직 상세화\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e결정 로직 이후의 로직을 조금씩 상세화 수행\n\u003cul\u003e\n\u003cli\u003e실패시 장애 조치(failover) 로직 등에 대해서 상세화 수행\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003eskinparam backgroundcolor transparent\n\n|컴포넌트1|\n|메인컴포넌트|\n|컴포넌트2|\n|메인컴포넌트|\nstart\n\nif (조건을 만족하는지?) then (예)\n        :위의 조건을 만족하는경우\n        병렬 프로세스를 시작;\n        fork\n                :컴포넌트1에 요청;\n        fork again\n                :컴포넌트2에 요청;\n        end fork\nelse (아니요)\n        repeat :다음 failover;\n        :재시도 수행;\n        repeat while (end of failovers?)\nendif\n\nstop\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-activity-main-detail.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch3 id=\"타컴포넌트의-처리-로직-상세화\"\u003e타컴포넌트의 처리 로직 상세화\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e타컴포넌트와 연동되는 부분에 대한 상세화\n\u003cul\u003e\n\u003cli\u003e타컴포넌트에서 요구되는 처리를 기반으로 작성\n\u003cul\u003e\n\u003cli\u003e해당 컴포넌트의 흐름을 컴포넌트 개발자들 간의 합의 및 설계\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-plantuml\" data-lang=\"plantuml\"\u003eskinparam backgroundcolor transparent\n\n|컴포넌트1|\n|메인컴포넌트|\n|컴포넌트2|\n|메인컴포넌트|\nstart\n\nif (조건을 만족하는지?) then (예)\n        :위의 조건을 만족하는경우\n        병렬 프로세스를 시작;\n        fork\n                :컴포넌트1에 요청;\n                |컴포넌트1|\n                :처리;\n                |메인컴포넌트|\n                :요청처리;\n        fork again\n                :컴포넌트2에 요청;\n                |컴포넌트2|\n                :처리;\n                |메인컴포넌트|\n                :요청처리;\n        end fork\nelse (아니요)\n        repeat :다음 failover;\n        :재시도 수행;\n        repeat while (end of failovers?)\nendif\n\nstop\n\u003c/code\u003e\u003c/pre\u003e\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/plantuml-activity-full.png\"/\u003e \n\u003c/figure\u003e\n\n"},{id:11,href:"https://hackartists.github.io/devel/introduction/",title:"Development",description:"This page introduces service development.",content:"\u003cp\u003e서비스를 개발하는 단계\u003c/p\u003e\n\u003ch2 id=\"주요-역할\"\u003e주요 역할\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e구현 방안 모색\u003c/li\u003e\n\u003cli\u003e기능 구현 및 리뷰\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"주요-스킬\"\u003e주요 스킬\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e신기술 학습 능력\u003c/li\u003e\n\u003cli\u003e오픈소스 활용 및 분석 능력\u003c/li\u003e\n\u003cli\u003e프로그래밍 능력\u003c/li\u003e\n\u003cli\u003e코드 및 이슈 관리 능력\u003c/li\u003e\n\u003c/ul\u003e\n"},{id:12,href:"https://hackartists.github.io/infra/docker/manage-db/",title:"DB 컨테이너 관리",description:"This page describes how to manage a database as a docker container.",content:"\u003ch2 id=\"mongodb-컨테이너-생성\"\u003eMongoDB 컨테이너 생성\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker\u003c/code\u003e 실행 명령어\u003c/li\u003e\n\u003c/ul\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003eFlags\u003c/th\u003e\n\u003cth\u003eDescription\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e-d\u003c/td\u003e\n\u003ctd\u003e컨테이너 터미널을 획득하지 않고, 디먼모드로 수행\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e-p\u003c/td\u003e\n\u003ctd\u003e컨테이너 PORT를 호스트(Host)로 바인딩\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e-v\u003c/td\u003e\n\u003ctd\u003e호스트의 파일 또는 디렉토리를 컨테이너로 마운트\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u0026ndash;name\u003c/td\u003e\n\u003ctd\u003e컨테이너 이름\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u0026ndash;restart\u003c/td\u003e\n\u003ctd\u003e재시작 정책 (\u003ccode\u003ealways\u003c/code\u003e 는 종료시 자동 재시작)\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker run -d -p 27017:27017 \u003cspan class=\"se\"\u003e\\\n\u003c/span\u003e\u003cspan class=\"se\"\u003e\u003c/span\u003e       --restart always \u003cspan class=\"se\"\u003e\\\n\u003c/span\u003e\u003cspan class=\"se\"\u003e\u003c/span\u003e       -v /Users/hackartist/data/docker/mongo/data:/data/db \u003cspan class=\"se\"\u003e\\\n\u003c/span\u003e\u003cspan class=\"se\"\u003e\u003c/span\u003e       --name mongo mongo\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch2 id=\"mongodb-관리\"\u003eMongoDB 관리\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eRobo 3T 와 같은 MongoDB 관리 GUI 툴 사용 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/2021-01-26_23-04-57_screenshot.png\"\n         alt=\"Figure 1: robo3t\"/\u003e \u003cfigcaption\u003e\n            \u003cp\u003eFigure 1: robo3t\u003c/p\u003e\n        \u003c/figcaption\u003e\n\u003c/figure\u003e\n\n\u003ch2 id=\"db-생성-및-데이터-입력\"\u003eDB 생성 및 데이터 입력\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003emongodb\u003c/code\u003e 에 접속해서 아래와 같이 샘플 데이터 생성\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-mongo\" data-lang=\"mongo\"\u003euse emacs\ndb.users.insert([\n    {\n        _id : ObjectId(\u0026quot;507f191e810c19729de860ea\u0026quot;),\n        title: \u0026quot;test\u0026quot;,\n        description: \u0026quot;test\u0026quot;,\n        tags: ['mongodb', 'database', 'NoSQL'],\n        likes: 100\n    },\n    {\n        title: \u0026quot;test2\u0026quot;,\n        description: \u0026quot;description2\u0026quot;,\n        tags: ['mongodb', 'database', 'NoSQL'],\n        likes: 100\n    },\n\n])\n\u003c/code\u003e\u003c/pre\u003e\u003ch2 id=\"데이터-조회\"\u003e데이터 조회\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e아래의 커맨드를 통해서 데이터 조회\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-mongo\" data-lang=\"mongo\"\u003edb.users.find()\n\u003c/code\u003e\u003c/pre\u003e"},{id:13,href:"https://hackartists.github.io/ops/introduction/",title:"Testing and Operations",description:"This page introduces how we monitor and test services.",content:"\u003cp\u003e서비스 및 기능을 테스트하고 운영하는 단계\u003c/p\u003e\n\u003ch2 id=\"주요-역할\"\u003e주요 역할\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e기능 테스트\u003c/li\u003e\n\u003cli\u003e장애 모니터링 및 관리\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"주요-스킬\"\u003e주요 스킬\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e테스트 케이스 정의 및 자동화 능력\u003c/li\u003e\n\u003cli\u003e장애 메트릭 분석 및 정의 능력\u003c/li\u003e\n\u003cli\u003e프로세스 수립 능력\u003c/li\u003e\n\u003c/ul\u003e\n"},{id:14,href:"https://hackartists.github.io/infra/docker/manage-image/",title:"도커 이미지 생성",description:"This page explains how to manage docker images.",content:"\u003ch2 id=\"도커-이미지-관리\"\u003e\u003cspan class=\"org-todo done DONE\"\u003eDONE\u003c/span\u003e 도커 이미지 관리\u003c/h2\u003e\n\u003ch3 id=\"도커-이미지란\"\u003e도커 이미지란?\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e컨테이너를 만들기 위한 템플릿\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"도커-이미지-조회\"\u003e도커 이미지 조회\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker images\u003c/code\u003e 로 조회\n\u003cul\u003e\n\u003cli\u003e레포지토리는 이미지들의 저장소를 의미함.\n\u003cul\u003e\n\u003cli\u003e통용적으로는 레포지토리의 마지막 \u003ccode\u003e/\u003c/code\u003e 뒤를 따서 이미지의 이름으로 부름.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e이미지는 단일 템플릿을 대상으로 하여, 해시 형태로 표현됨.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker images\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003eREPOSITORY\u003c/th\u003e\n\u003cth\u003eTAG\u003c/th\u003e\n\u003cth\u003eIMAGE\u003c/th\u003e\n\u003cth\u003eID\u003c/th\u003e\n\u003cth\u003eCREATED\u003c/th\u003e\n\u003cth\u003eSIZE\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003eubuntu\u003c/td\u003e\n\u003ctd\u003elatest\u003c/td\u003e\n\u003ctd\u003eadafef2e596e\u003c/td\u003e\n\u003ctd\u003e7\u003c/td\u003e\n\u003ctd\u003emonths  ago\u003c/td\u003e\n\u003ctd\u003e73.9MB\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eubuntu\u003c/td\u003e\n\u003ctd\u003e18.04\u003c/td\u003e\n\u003ctd\u003ed27b9ffc5667\u003c/td\u003e\n\u003ctd\u003e7\u003c/td\u003e\n\u003ctd\u003emonths  ago\u003c/td\u003e\n\u003ctd\u003e64.2MB\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003emongo\u003c/td\u003e\n\u003ctd\u003e4.2.3\u003c/td\u003e\n\u003ctd\u003ebcef5fd2979d\u003c/td\u003e\n\u003ctd\u003e11\u003c/td\u003e\n\u003ctd\u003emonths  ago\u003c/td\u003e\n\u003ctd\u003e386MB\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch3 id=\"도커-이미지-정리\"\u003e도커 이미지 정리\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e사용하지 않는 이미지 정리\n\u003cul\u003e\n\u003cli\u003e현재 컨테이너로 만들어져 있지 않은 모든 이미지 삭제\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker image prune -f\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003cul\u003e\n\u003cli\u003e사용하지 않는 볼륨 정리\n\u003cul\u003e\n\u003cli\u003e컨테이너에 마운팅 되지 않은 볼륨 삭제\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker volume prune -f\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003cul\u003e\n\u003cli\u003e유사한 형태로 사용자하지 않는 \u003ccode\u003econtainer\u003c/code\u003e 등도 삭제 할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"도커-이미지-수정\"\u003e\u003cspan class=\"org-todo done DONE\"\u003eDONE\u003c/span\u003e 도커 이미지 수정\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e도커 이미지의 라이프 사이클\n\u003col\u003e\n\u003cli\u003e도커 이미지에서 컨테이너 생성\u003c/li\u003e\n\u003cli\u003e컨테이너 수정 작업 수행\u003c/li\u003e\n\u003cli\u003e컨테이너 작업 내용을 이미지에 커밋(commit)\u003c/li\u003e\n\u003cli\u003e이미지를 저장소(repository)에 업로드(push)\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/docker-life-cycle.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch3 id=\"나만의-도커-이미지-만들기\"\u003e나만의 도커 이미지 만들기\u003c/h3\u003e\n\u003ch4 id=\"베이스-컨테이너-생성\"\u003e베이스 컨테이너 생성\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003earchlinux\u003c/code\u003e 를 이용하여 컨테이너 생성\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker run -it --name archlinux archlinux\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"컨테이너-내용-수정\"\u003e컨테이너 내용 수정\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e컨테이너에 파일 생성\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003e\u003cspan class=\"nb\"\u003eecho\u003c/span\u003e \u003cspan class=\"s2\"\u003e\u0026#34;new file\u0026#34;\u003c/span\u003e \u0026gt;\u0026gt; /root/readme.md\n\u003cspan class=\"nb\"\u003eexit\u003c/span\u003e\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"컨테이너-커밋-및-이미지-생성\"\u003e컨테이너 커밋 및 이미지 생성\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ecommit\u003c/code\u003e 하위명령어를 이용하여 이미지 생성\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker commit -m \u0026quot;{{message}}\u0026quot; {{container-name}} {{image-repository}}:{{tag-name}}\u003c/code\u003e\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker commit -m \u003cspan class=\"s2\"\u003e\u0026#34;my own image\u0026#34;\u003c/span\u003e archlinux hackartist/my-own-image:latest\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eimages\u003c/code\u003e 하위명령어를 이용하여 이미지 목록 확인\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker images\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003eREPOSITORY\u003c/th\u003e\n\u003cth\u003eTAG\u003c/th\u003e\n\u003cth\u003eIMAGE\u003c/th\u003e\n\u003cth\u003eID\u003c/th\u003e\n\u003cth\u003eCREATED\u003c/th\u003e\n\u003cth\u003eSIZE\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003ehackartist/my-own-image\u003c/td\u003e\n\u003ctd\u003elatest\u003c/td\u003e\n\u003ctd\u003e3b7256abb727\u003c/td\u003e\n\u003ctd\u003e8\u003c/td\u003e\n\u003ctd\u003eminutes  ago\u003c/td\u003e\n\u003ctd\u003e406MB\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003ehackartist/docker-dns\u003c/td\u003e\n\u003ctd\u003elatest\u003c/td\u003e\n\u003ctd\u003ea006dfefbbbf\u003c/td\u003e\n\u003ctd\u003e7\u003c/td\u003e\n\u003ctd\u003emonths   ago\u003c/td\u003e\n\u003ctd\u003e422MB\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003erun\u003c/code\u003e 하위명령어를 통해서 컨테이너 생성 후 확인\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker run -it --name myarch hackartist/my-own-image:latest\ncat /root/readme.md\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch2 id=\"도커-이미지-빌드\"\u003e\u003cspan class=\"org-todo done DONE\"\u003eDONE\u003c/span\u003e 도커 이미지 빌드\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"#%ec%bb%a8%ed%85%8c%ec%9d%b4%eb%84%88-%ec%bb%a4%eb%b0%8b-%eb%b0%8f-%ec%9d%b4%eb%af%b8%ec%a7%80-%ec%83%9d%ec%84%b1\" \u003e컨테이너 커밋 및 이미지 생성\u003c/a\u003e와 유사하지만, 소스코드의 빌드와 이미지 생성 가능\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"https://github.com/hackartists/dockerize\"  target=\"_blank\" rel=\"noopener\"\n    \u003eDockerize github\u003c/a\u003e에서 코드 확인\n\u003col\u003e\n\u003cli\u003e코드 개발\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eDockerfile\u003c/code\u003e 스크립트 작성\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003edocker build\u003c/code\u003e 를 이용하여 이미지 빌드\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"간단한-예제-코드-개발\"\u003e간단한 예제 코드 개발\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ego\u003c/code\u003e 개발 언어로 헬로우 월드를 개발\n\u003cul\u003e\n\u003cli\u003e상세 내용은 개발 섹션을 참고\u003c/li\u003e\n\u003cli\u003e파일 이름은 \u003ccode\u003emain.go\u003c/code\u003e 로 지정\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-go\" data-lang=\"go\"\u003e\u003cspan class=\"kn\"\u003epackage\u003c/span\u003e \u003cspan class=\"nx\"\u003emain\u003c/span\u003e\n\n\u003cspan class=\"kn\"\u003eimport\u003c/span\u003e \u003cspan class=\"s\"\u003e\u0026#34;fmt\u0026#34;\u003c/span\u003e\n\n\u003cspan class=\"kd\"\u003efunc\u003c/span\u003e \u003cspan class=\"nf\"\u003emain\u003c/span\u003e\u003cspan class=\"p\"\u003e()\u003c/span\u003e \u003cspan class=\"p\"\u003e{\u003c/span\u003e\n  \u003cspan class=\"nx\"\u003efmt\u003c/span\u003e\u003cspan class=\"p\"\u003e.\u003c/span\u003e\u003cspan class=\"nf\"\u003ePrintln\u003c/span\u003e\u003cspan class=\"p\"\u003e(\u003c/span\u003e\u003cspan class=\"s\"\u003e\u0026#34;hello world\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e)\u003c/span\u003e\n\u003cspan class=\"p\"\u003e}\u003c/span\u003e\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"예제-코드-실행\"\u003e예제 코드 실행\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ego mod init {{package name}}\u003c/code\u003e 은 의존성 관리 및 \u003ccode\u003eGOPATH\u003c/code\u003e 가 아닌 곳에서 빌드를 위한 프로젝트 관리\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ego build\u003c/code\u003e 를 통해서 해당 프로그램을 빌드\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e-o\u003c/code\u003e 옵션으로 실행 파일 이름 지정\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003ego mod init github.com/hackartists/dockerize\ngo build -o app\n./app\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch3 id=\"dockerfile-활용\"\u003eDockerfile 활용\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker build\u003c/code\u003e 를 통해서 이미지 생성\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e-f\u003c/code\u003e 옵션으로 \u003ccode\u003eDockerfile\u003c/code\u003e 이름 설정\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e./Dockerfile\u003c/code\u003e 은 기본 설정이라서 생략 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e-t\u003c/code\u003e 옵션으로 레포지토리 및 태그 이름을 지정\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e.\u003c/code\u003e 은 도커 컨텍스트 디렉토리를 의미\n\u003cul\u003e\n\u003cli\u003e지정된 디렉토리 이하로 모든 파일을 도커 빌드를 위해서 로딩함.\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e.dockerignore\u003c/code\u003e 를 통해서 불필요한 디렉토리를 제외할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker build -f Dockerfile -t hackartist/go-hello-world .\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"dockerfile-스크립트\"\u003eDockerfile 스크립트\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e빌드를 위한 최초 이미지 선택\n\u003cul\u003e\n\u003cli\u003e위의 예제는 \u003ccode\u003ego\u003c/code\u003e 언어를 사용하기 때문에 \u003ccode\u003egolang:latest\u003c/code\u003e 이미지를 활용\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e빌드 커맨드 수행\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ego build -o app\u003c/code\u003e 으로 빌드 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-dockerfile\" data-lang=\"dockerfile\"\u003e\u003cspan class=\"k\"\u003eFROM\u003c/span\u003e\u003cspan class=\"s\"\u003e golang:latest\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eADD\u003c/span\u003e . /workdir\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eWORKDIR\u003c/span\u003e\u003cspan class=\"s\"\u003e /workdir\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eRUN\u003c/span\u003e go build -o app\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eCMD\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\u003cspan class=\"s2\"\u003e\u0026#34;/workdir/app\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e]\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"도커-업로드--push--하기\"\u003e도커 업로드(push) 하기\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e생성한 도커 이미지를 해당 레포지토리에 업로드\n\u003cul\u003e\n\u003cli\u003e도메인 이름이 없는 경우 자동으로 \u003ccode\u003edocker.io\u003c/code\u003e 가 추가됨.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker push hackartist/go-hello-world\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e"},{id:15,href:"https://hackartists.github.io/infra/docker/docker-build-advanced/",title:"도커 빌드 고급 사용법",description:"description",content:"\u003ch2 id=\"dockerignore-활용\"\u003e\u003ccode\u003eDockerignore\u003c/code\u003e 활용\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker build\u003c/code\u003e 수행시 모든 하위 디렉토리를 컨텍스트로 로딩\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ebuild\u003c/code\u003e 디렉토리 등이 포함될 때는 컨테스트 로딩에 시간이 길어짐.\u003c/li\u003e\n\u003cli\u003e특정 디렉토리를 컨텍스트에서 제외할 필요가 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e.dockerignore\u003c/code\u003e 파일을 생성하여 디렉토리 필터링 수행\n\u003cul\u003e\n\u003cli\u003e기본적으로 디렉토리 이름이 들어가지만 몇가지 유용한 문법을 지원\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ebuild\u003c/code\u003e 디렉토리 제외\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e*/temp*\u003c/code\u003e 1 레벨 하위 디렉토리에서 \u003ccode\u003etemp\u003c/code\u003e 로 시작하는 디렉토리 제외\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e*/*/temp*\u003c/code\u003e 2 레벨 하위 디렉토리에서 \u003ccode\u003etemp\u003c/code\u003e 로 시작하는 디렉토리 제외\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003etemp?\u003c/code\u003e 는 \u003ccode\u003etemp\u003c/code\u003e 로 시작하고 다음에 한글자가 더 있는 디렉토리 제외\n\u003cul\u003e\n\u003cli\u003e예) \u003ccode\u003etempa\u003c/code\u003e , \u003ccode\u003etempb\u003c/code\u003e 등\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-text\" data-lang=\"text\"\u003e# comment\nbuild\n*/temp*\n*/*/temp*\ntemp?\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch2 id=\"도커-빌드-이미지-분리\"\u003e도커 빌드 이미지 분리\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"/infra/docker/manage-image/\" \u003eDockerfile 스크립트\u003c/a\u003e 에서 코드를 빌드하여 이미지를 만드는 방법을 설명\n\u003cul\u003e\n\u003cli\u003e빌드시에는 서비스 운영에 필요하지 않은 파일도 존재\u003c/li\u003e\n\u003cli\u003e운영 환경의 최적화를 위해서 빌드이미지와 배포이미지 분리\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e아래와 같이 \u003ccode\u003eas build\u003c/code\u003e 형태로 빌드 환경에 이름을 붙임\n\u003cul\u003e\n\u003cli\u003e동일한 원리로 다양한 이미지 환경을 하나의 \u003ccode\u003eDockerfile\u003c/code\u003e 에 정의할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e배포 이미지에서는 \u003ccode\u003e--from={{name}}\u003c/code\u003e 을 통해서 특정 이름의 이미지에서 파일 복사 등을 수행\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003egolang:latest\u003c/code\u003e 이미지는 \u003ccode\u003edebian:buster\u003c/code\u003e 를 기반으로 하고 있어서, 동일한 환경으로 배포 이미지 선택\u003c/li\u003e\n\u003cli\u003e동일한 원리로 위에서 여러개의 이미지를 정의했다면 각각의 환경에서 복사할 수 있음\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-dockerfile\" data-lang=\"dockerfile\"\u003e\u003cspan class=\"k\"\u003eFROM\u003c/span\u003e\u003cspan class=\"s\"\u003e golang:latest as build\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eADD\u003c/span\u003e . /workdir\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eWORKDIR\u003c/span\u003e\u003cspan class=\"s\"\u003e /workdir\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eRUN\u003c/span\u003e go build -o app\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eFROM\u003c/span\u003e\u003cspan class=\"s\"\u003e debian/buster\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eWORKDIR\u003c/span\u003e\u003cspan class=\"s\"\u003e /app\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eCOPY\u003c/span\u003e --from\u003cspan class=\"o\"\u003e=\u003c/span\u003ebuild /workdir/app /app/app\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003cspan class=\"err\"\u003e\u003c/span\u003e\u003cspan class=\"k\"\u003eCMD\u003c/span\u003e \u003cspan class=\"p\"\u003e[\u003c/span\u003e\u003cspan class=\"s2\"\u003e\u0026#34;/app/app\u0026#34;\u003c/span\u003e\u003cspan class=\"p\"\u003e]\u003c/span\u003e\u003cspan class=\"err\"\u003e\n\u003c/span\u003e\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e"},{id:16,href:"https://hackartists.github.io/blog/%EB%B8%94%EB%A1%9C%EA%B7%B8-%EC%86%8C%EA%B0%9C/",title:"블로그 소개",description:"This page introduces the purpose of this blog.",content:"\u003cp\u003e본 블로그는 서비스를 개발하고 운영하는데 필요한 기술에 대해서 스스로 공부하고 정리해나가기 위해서 만들어졌습니다.\u003c/p\u003e\n\u003cp\u003e잘못된 정보나 추가로 필요한 정보들은 많은 피드백 주시길 바랍니다.\u003c/p\u003e\n"},{id:17,href:"https://hackartists.github.io/infra/docker/docker-compose/",title:"다중 컨테이너 관리",description:"This page explains how to manage multiple dockers.",content:"\u003ch2 id=\"도커-컴포즈--docker-compose--소개\"\u003e도커 컴포즈(Docker compose) 소개\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e도커 컴포즈는 여러 개의 도커로 구성되는 네트워크를 하나의 파일로 관리\n\u003cul\u003e\n\u003cli\u003e네트워크를 정의\u003c/li\u003e\n\u003cli\u003e다수의 컨테이너를 정의\u003c/li\u003e\n\u003cli\u003e각 컨테이너는 이미지, 환경 변수, 포트 정보 등을 정의\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/docker-compose-prosess.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch2 id=\"도커네트워크-설정\"\u003e도커네트워크 설정\u003c/h2\u003e\n\u003ch3 id=\"네트워크-정보-설정\"\u003e네트워크 정보 설정\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e각자 사용하고자 하는 도커 개발 네트워크의 이름 설정\n\u003cul\u003e\n\u003cli\u003e본 블로그에서는 \u003ccode\u003edev-net\u003c/code\u003e 이라고 설정\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003edevnet\u003c/code\u003e 의 IP 대역을 \u003ccode\u003e192.168.100.0/24\u003c/code\u003e 로 설정\n\u003cul\u003e\n\u003cli\u003e즉, 해당 네트워크에 포함되는 모든 도커 컨테이너는 \u003ccode\u003e192.168.100.x\u003c/code\u003e 의 IP를 가진다는 것을 의미함.\u003c/li\u003e\n\u003cli\u003e위의 IP 표기를 CIDR 표기라고 하는데, 이는 추후에 네트워크에서 다룰 예정임.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"도커-네트워크-생성\"\u003e도커 네트워크 생성\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"#%eb%84%a4%ed%8a%b8%ec%9b%8c%ed%81%ac-%ec%a0%95%eb%b3%b4-%ec%84%a4%ec%a0%95\" \u003e네트워크 정보 설정\u003c/a\u003e 에서 기술한 정보를 이용하여 도커 네트워크를 생성\n\u003cul\u003e\n\u003cli\u003e도커 컴포즈에서 자동으로 생성하는 방법도 있으나, 수동 생성하는 것으로 사용하는 것에 대해서만 설명\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eMac OS\u003c/code\u003e 를 기준으로 자동 생성보다, 수동 생성을 추천하며, 도커 virtual private network(VPN) 활용편에서 설명\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker network create --attachable --subnet 192.168.100.0/24 devnet\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch2 id=\"도커-컨테이너-설정\"\u003e도커 컨테이너 설정\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e이 단계에서는 필요한 컨테이너들에 대한 정보를 설정\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"이미지-수집\"\u003e이미지 수집\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e사용하고자 하는 이미지를 선택\u003c/li\u003e\n\u003c/ul\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e사용용도\u003c/th\u003e\n\u003cth\u003e이미지\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e데이터베이스\u003c/td\u003e\n\u003ctd\u003emongo:4\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e애플리케이션 서버\u003c/td\u003e\n\u003ctd\u003egolang:1.15\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch3 id=\"컨테이너별-정보-설정\"\u003e컨테이너별 정보 설정\u003c/h3\u003e\n\u003ch4 id=\"컨테이너별-이미지-설정\"\u003e컨테이너별 이미지 설정\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e각 컨테이너에 대한 이름 및 이미지 설정\u003c/li\u003e\n\u003c/ul\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e용도\u003c/th\u003e\n\u003cth\u003e컨테이너 이름\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e데이터베이스\u003c/td\u003e\n\u003ctd\u003emongodb\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e개발 서버\u003c/td\u003e\n\u003ctd\u003egreeting-server\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch4 id=\"컨테이너별-환경-변수-설정\"\u003e컨테이너별 환경 변수 설정\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e각 컨테이너별로 환경변수 설정이 필요한 경우가 있음.\n\u003cul\u003e\n\u003cli\u003e각 컨테이너별로 어떤 환경변수를 설정할지 결정\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e컨테이너 이름\u003c/th\u003e\n\u003cth\u003e환경변수\u003c/th\u003e\n\u003cth\u003e값\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003emongodb\u003c/td\u003e\n\u003ctd\u003eMONGO_INITDB_ROOT_USERNAME\u003c/td\u003e\n\u003ctd\u003eroot\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003emongodb\u003c/td\u003e\n\u003ctd\u003eMONGO_INITDB_ROOT_PASSWORD\u003c/td\u003e\n\u003ctd\u003eroot\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch4 id=\"컨테이너별-포트-설정\"\u003e컨테이너별 포트 설정\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e호스트 머신의 특정 포트를 컨테이너의 포트에 바인딩하기 위해서 사용\u003c/li\u003e\n\u003cli\u003e호스트에서 게스트 머신으로 접근하기 위해서는 2가지 방법이 있음.\n\u003col\u003e\n\u003cli\u003e컨테이너의 IP로 접근 하는 방법\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eMac OS\u003c/code\u003e 에서는 기본적으로 안됨.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e호스트 머신의 포트로 매핑하여 접근하는 방법\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003elocalhost\u003c/code\u003e 에 바인딩된 포트를 통해서 접근\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e컨테이너 이름\u003c/th\u003e\n\u003cth\u003e호스트 포트\u003c/th\u003e\n\u003cth\u003e컨테이너 포트\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003emongodb\u003c/td\u003e\n\u003ctd\u003e27017\u003c/td\u003e\n\u003ctd\u003e27017\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003egreeting-server\u003c/td\u003e\n\u003ctd\u003e3000\u003c/td\u003e\n\u003ctd\u003e3000\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch4 id=\"컨테이너별-마운트-정보-설정\"\u003e컨테이너별 마운트 정보 설정\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e호스트의 특정 경로를 컨테이너에 마운트할 때 사용\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ePROJECT_ROOT\u003c/code\u003e 는 \u003ccode\u003e/home/hackartist/data/greeting-server\u003c/code\u003e 로 가정함\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003e컨테이너 이름\u003c/th\u003e\n\u003cth\u003e호스트 경로\u003c/th\u003e\n\u003cth\u003e컨테이너 경로\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003emongodb\u003c/td\u003e\n\u003ctd\u003e$PROJECT_ROOT/.build/data\u003c/td\u003e\n\u003ctd\u003e/data/db\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003egreeting-server\u003c/td\u003e\n\u003ctd\u003e$PROJECT_ROOT\u003c/td\u003e\n\u003ctd\u003e/workdir\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch2 id=\"도커-컴포즈-설정\"\u003e도커 컴포즈 설정\u003c/h2\u003e\n\u003ch3 id=\"docker-compose-dot-yaml-파일-작성\"\u003edocker-compose.yaml 파일 작성\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"#%eb%8f%84%ec%bb%a4-%ec%bb%a8%ed%85%8c%ec%9d%b4%eb%84%88-%ec%84%a4%ec%a0%95\" \u003e도커 컨테이너 설정\u003c/a\u003e 에서 설정한 정보를 기반으로 도커 컴포즈를 구성\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003enetworks\u003c/code\u003e 옵션으로 외부에서 생성한 네트워크를 사용하여 생성되도록 설정\n\u003cul\u003e\n\u003cli\u003e해당 네트워크의 IP 주소를 가지게 됨\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eservices\u003c/code\u003e 섹션에 각 컨테이너에 대한 정보를 기술\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003eservices\u003c/code\u003e 섹션은 크게 \u003ccode\u003emongodb\u003c/code\u003e, \u003ccode\u003egreeting-server\u003c/code\u003e 로 구성\n\u003cul\u003e\n\u003cli\u003e가장 상위의 이름은 도커 컴포즈 네트워크 상에서 각 컨테이너를 위한 도메인 이름으로 사용됨.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003erestart\u003c/code\u003e 옵션을 통해서 컴퓨터 재시작 시에 자동으로 시작되도록 설정 가능\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eports\u003c/code\u003e, \u003ccode\u003eenvironment\u003c/code\u003e, \u003ccode\u003evolumes\u003c/code\u003e 섹션을 이용하여 위에서 정의된 항목에 대한 설정 수행\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eworking_dir\u003c/code\u003e 은 해당 컨테이너가 시작할 때 경로를 의미\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003ecommand\u003c/code\u003e 는 해당 컨테이너가 시작할 때, 수행되는 커맨드\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ego run main.go\u003c/code\u003e 는 \u003ccode\u003egreeting-server\u003c/code\u003e 를 개발용으로 실행하는 커맨드\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-docker-compose\" data-lang=\"docker-compose\"\u003eversion: \u0026quot;3.8\u0026quot;\n\nnetworks:\n  default:\n    external:\n      name: devnet\n\nservices:\n  mongodb:\n    image: mongo:4\n    container_name: mongodb\n    restart: always\n    ports:\n      - 27017:27017\n    environment:\n      - MONGO_INITDB_ROOT_USERNAME: root\n      - MONGO_INITDB_ROOT_PASSWORD: root\n    volumes:\n      - $PROJECT_ROOT/.build/data:/data/db\n  greeting-server:\n    image: golang:1.15\n    container_name: greeting-server\n    restart: always\n    ports:\n      - 3000:3000\n    volumes:\n      - $PROJECT_ROOT:/workdir\n    working_dir: /workdir\n    command: go run main.go\n\u003c/code\u003e\u003c/pre\u003e\u003ch3 id=\"도커-컴포즈-실행\"\u003e도커 컴포즈 실행\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"#docker-compose-dot-yaml-%ed%8c%8c%ec%9d%bc-%ec%9e%91%ec%84%b1\" \u003edocker-compose.yaml 파일 작성\u003c/a\u003e 섹션에서 작성된 파일 사용법\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ePROJECT_ROOT\u003c/code\u003e 는 yaml 파일에서 사용하는 환경 변수 전달\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e-f\u003c/code\u003e 는 도커 컴포즈 파일 이름을 기술\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker-compose.yaml\u003c/code\u003e 인 경우에는 생략 가능\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e-p\u003c/code\u003e 는 도커 스택의 이름으로 추후 관리에 용이함.\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003eup\u003c/code\u003e 은 도커 컴포즈를 구성하는 명령어\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e-d\u003c/code\u003e 옵션은 디먼 모드로 동작하는 옵션, 생략하면 도커 컴포즈 로그를 볼 수 있음.\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003emongodb\u003c/code\u003e 만 수행하고 싶은 경우는 \u003ccode\u003e... up -d mongodb\u003c/code\u003e 명령어를 사용\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003e\u003cspan class=\"nv\"\u003ePROJECT_ROOT\u003c/span\u003e\u003cspan class=\"o\"\u003e=\u003c/span\u003e/home/hackartist/data/greeting-server \u003cspan class=\"se\"\u003e\\\n\u003c/span\u003e\u003cspan class=\"se\"\u003e\u003c/span\u003e            docker-compose -f docker-compose.yaml -p greeting-server up -d\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch3 id=\"도커-컴포즈-종료\"\u003e도커 컴포즈 종료\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e수행된 도커 컴포즈를 종료하고 싶은 경우에 \u003ccode\u003edown\u003c/code\u003e 을 사용할 수 있음.\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e--remove-orphans\u003c/code\u003e 는 어떤 사유로 해당 컴포즈 소속이지만, 이전에 종료되지 않은 컨테이너를 모두 종료하는 옵션\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003e\u003cspan class=\"nv\"\u003ePROJECT_ROOT\u003c/span\u003e\u003cspan class=\"o\"\u003e=\u003c/span\u003e/home/hackartist/data/greeting-server \u003cspan class=\"se\"\u003e\\\n\u003c/span\u003e\u003cspan class=\"se\"\u003e\u003c/span\u003e            docker-compose -f docker-compose.yaml -p greeting-server down --remove-orphans\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e"},{id:18,href:"https://hackartists.github.io/infra/docker/docker-vpn/",title:"도커 VPN 활용편",description:"This page describes how to integrate network and communication with containers on Mac OS via VPN.",content:"\u003ch2 id=\"도커-네트워크-개요-및-제약사항\"\u003e도커 네트워크 개요 및 제약사항\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e도커 네트워크는 도커들 간의 사설 네트워크가 구축되고, 호스트 머신과 \u003ccode\u003ebridge\u003c/code\u003e 인터페이스를 통해서 통신\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eMac OS의 도커는 가상 머신(virtual machine) 에서 구동되는 것이기 때문에, \u003ccode\u003ebridge\u003c/code\u003e 가 없음.\u003c/li\u003e\n\u003cli\u003e따라서, Mac OS 에서는 호스트 머신과 도커 컨테이너들이 직접적으로 통신할 수 없음.\n\u003cul\u003e\n\u003cli\u003e상세한 내용은 \u003ca class=\"link\" href=\"https://docs.docker.com/docker-for-mac/networking/\"  target=\"_blank\" rel=\"noopener\"\n    \u003e도커 네트워크\u003c/a\u003e를 참고\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eMac OS 에서 호스트 머신이 컨테이너에 접근하기 위해서, \u003ccode\u003e-p\u003c/code\u003e 옵션을 통해 포트 바인딩이 필요함.\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e많은 포트가 바인딩되는 경우 이에 대한 관리가 어려움\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"vpn을-이용한-호스트-머신과-도커-네트워크-터널링\"\u003eVPN을 이용한 호스트 머신과 도커 네트워크 터널링\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e호스트 머신을 도커 네트워크에 virtual private network(VPN)으로 연결하여 라우팅 수행\n\u003cul\u003e\n\u003cli\u003eVPN 의 개념은 네트워크 섹션을 참고\u003c/li\u003e\n\u003cli\u003eVPN 터널링을 통해서 \u003ca class=\"link\" href=\"/infra/docker/docker-compose/\" \u003e도커 네트워크 생성\u003c/a\u003e 에서 생성된 주소는 해당 VPN 으로 라우팅되도록 설정\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003eVPN 터널링 및 라우팅 설정이 된 이후에는 도커 컨테이너에 접속할 때 별도 포트바인딩이 필요없음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"vpn-터널링-및-라우팅-설정-절차\"\u003eVPN 터널링 및 라우팅 설정 절차\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e본 섹션에서는 Open VPN 을 통해서 설정하는 방법에 대해서 설명\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/vpn-wbs.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch2 id=\"open-vpn-설정\"\u003eOpen VPN 설정\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eOpen VPN 을 설정하기 위해서 \u003ca class=\"link\" href=\"https://hub.docker.com/r/kylemanna/openvpn\"  target=\"_blank\" rel=\"noopener\"\n    \u003ekylemanna/openvpn\u003c/a\u003e 이미지를 사용\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id=\"open-vpn-사전-설정\"\u003eOpen VPN 사전 설정\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e사전 설정 단계에서는 컨테이너가 구동되기 전에 필요한 설정 작업을 미리 수행\n\u003cul\u003e\n\u003cli\u003eOpen VPN 으로 발급된 인증서에 기술할 도메인 이름 등을 설정\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch4 id=\"도커-볼륨-생성\"\u003e도커 볼륨 생성\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e도커 볼륨 크게 두가지 방법을 사용할 수 있음.\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003edocker volume\u003c/code\u003e 으로 생성하는 실제 도커의 볼륨\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e호스트 경로\u003c/code\u003e 를 도커 볼륨으로 사용\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003e\u003cspan class=\"c1\"\u003e## 도커 볼륨 사용시\u003c/span\u003e\n\u003cspan class=\"nb\"\u003eexport\u003c/span\u003e \u003cspan class=\"nv\"\u003eOVPN_DATA\u003c/span\u003e\u003cspan class=\"o\"\u003e=\u003c/span\u003eovpn-data\ndocker volume create --name \u003cspan class=\"nv\"\u003e$OVPN_DATA\u003c/span\u003e\n\n\u003cspan class=\"c1\"\u003e## 호스트 경로 사용시\u003c/span\u003e\n\u003cspan class=\"nb\"\u003eexport\u003c/span\u003e \u003cspan class=\"nv\"\u003eOVPN_DATA\u003c/span\u003e\u003cspan class=\"o\"\u003e=\u003c/span\u003e\u003cspan class=\"k\"\u003e$(\u003c/span\u003e\u003cspan class=\"nb\"\u003epwd\u003c/span\u003e\u003cspan class=\"k\"\u003e)\u003c/span\u003e/openvpn \u003cspan class=\"c1\"\u003e# 호스트 머신에서 설정파일을 저장하고자 하는 경로\u003c/span\u003e\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"pki-구조-초기화\"\u003ePKI 구조 초기화\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003ePKI 구조는 인증서를 발급/검증하기 위한 구조로 Open VPN 에서 인증서 발급 구조로 사용\n\u003cul\u003e\n\u003cli\u003e상세 설명은 네트워크 섹션 참고\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003ePKI 구조를 만들기 위해서 아래와 같은 절차를 거침.\n\u003col\u003e\n\u003cli\u003ePKI 구조를 위한 설정 파일 생성\u003c/li\u003e\n\u003cli\u003ePKI 구조 생성\u003c/li\u003e\n\u003c/ol\u003e\n\u003c/li\u003e\n\u003cli\u003e아래의 명령어를 수행하기 전에 \u003ca class=\"link\" href=\"#%eb%8f%84%ec%bb%a4-%eb%b3%bc%eb%a5%a8-%ec%83%9d%ec%84%b1\" \u003e도커 볼륨 생성\u003c/a\u003e은 이미 완료되어야 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker run -v \u003cspan class=\"nv\"\u003e$OVPN_DATA\u003c/span\u003e:/etc/openvpn --rm kylemanna/openvpn:2.4 ovpn_genconfig -u udp://localhost\ndocker run -v \u003cspan class=\"nv\"\u003e$OVPN_DATA\u003c/span\u003e:/etc/openvpn --rm -it kylemanna/openvpn:2.4 ovpn_initpki\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch3 id=\"open-vpn-컨테이너-설정\"\u003eOpen VPN 컨테이너 설정\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e아래와 같이 도커 컴포즈 설정 파일을 작성\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"/infra/docker/docker-compose/\" \u003e도커 네트워크 생성\u003c/a\u003e에서 생성된 네트워크를 사용\n\u003cul\u003e\n\u003cli\u003e해당 네트워크를 사용해야지 개발용 도커와 연계할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e호스트 경로가 아닌 도커 볼륨을 사용하는 경우에는 코멘트 삭제\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-docker-compose\" data-lang=\"docker-compose\"\u003eversion: \u0026quot;3.9\u0026quot;\n\nnetworks:\n  default:\n    external:\n      name: devnet\n\nservices:\n  vpn.docker:\n    restart: always\n    container_name: vpn.docker\n    image: kylemanna/openvpn:2.4\n    ports:\n       - 1194:1194/udp\n    volumes:\n      - $OVPN_DATA:/etc/openvpn\n    cap_add:\n      - NET_ADMIN\n\n# volumes:\n#   ovpn-data:\n#     external: true\n\u003c/code\u003e\u003c/pre\u003e\u003ch3 id=\"open-vpn-컨테이너-실행\"\u003eOpen VPN 컨테이너 실행\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"#open-vpn-%ec%bb%a8%ed%85%8c%ec%9d%b4%eb%84%88-%ec%84%a4%ec%a0%95\" \u003eOpen VPN 컨테이너 설정\u003c/a\u003e 에서 작성된 도커 컴포즈를 실행\n\u003cul\u003e\n\u003cli\u003eOpen VPN 도커를 실행하기 전에 \u003ca class=\"link\" href=\"#pki-%ea%b5%ac%ec%a1%b0-%ec%b4%88%ea%b8%b0%ed%99%94\" \u003ePKI 구조 초기화\u003c/a\u003e가 선행 되어야 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003edocker-compose -p infra up -d\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch2 id=\"ovpn-인증서-설정\"\u003eOVPN 인증서 설정\u003c/h2\u003e\n\u003ch3 id=\"ovpn-인증서-발급\"\u003eOVPN 인증서 발급\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003eVPN에 접속할 때, 사용할 인증서 발급\n\u003cul\u003e\n\u003cli\u003e두번째 단계에서 \u003ca class=\"link\" href=\"#pki-%ea%b5%ac%ec%a1%b0-%ec%b4%88%ea%b8%b0%ed%99%94\" \u003ePKI 구조 초기화\u003c/a\u003e 단계에서 입력한 비밀번호 입력 필요\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e인증서 발급이 완료되고 나면 \u003ccode\u003e$NAME.ovpn\u003c/code\u003e 파일이 생성됨.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003e\u003cspan class=\"nb\"\u003eexport\u003c/span\u003e \u003cspan class=\"nv\"\u003eNAME\u003c/span\u003e\u003cspan class=\"o\"\u003e=\u003c/span\u003ehackartist\ndocker run -v \u003cspan class=\"nv\"\u003e$OVPN_DATA\u003c/span\u003e:/etc/openvpn --rm -it kylemanna/openvpn easyrsa build-client-full \u003cspan class=\"nv\"\u003e$NAME\u003c/span\u003e nopass\ndocker run -v \u003cspan class=\"nv\"\u003e$OVPN_DATA\u003c/span\u003e:/etc/openvpn --rm kylemanna/openvpn ovpn_getclient \u003cspan class=\"nv\"\u003e$NAME\u003c/span\u003e \u0026gt; \u003cspan class=\"nv\"\u003e$NAME\u003c/span\u003e.ovpn\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch3 id=\"인증서-수정\"\u003e인증서 수정\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e생성된 인증서를 텍스트 에디터로 열기\n\u003cul\u003e\n\u003cli\u003e아래와 같은 형태의 인증서가 나온것을 확인할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-text\" data-lang=\"text\"\u003eclient\nnobind\ndev tun\nremote-cert-tls server\n\nremote localhost 1194 udp\n\n\u0026lt;key\u0026gt;\n-----BEGIN PRIVATE KEY-----\n... 생략 ...\n-----END PRIVATE KEY-----\n\u0026lt;/key\u0026gt;\n\u0026lt;cert\u0026gt;\n-----BEGIN CERTIFICATE-----\n... 생략 ...\n-----END CERTIFICATE-----\n\u0026lt;/cert\u0026gt;\n\u0026lt;ca\u0026gt;\n-----BEGIN CERTIFICATE-----\n... 생략 ...\n-----END CERTIFICATE-----\n\u0026lt;/ca\u0026gt;\nkey-direction 1\n\u0026lt;tls-auth\u0026gt;\n#\n# 2048 bit OpenVPN static key\n#\n-----BEGIN OpenVPN Static key V1-----\n... 생략 ...\n-----END OpenVPN Static key V1-----\n\u0026lt;/tls-auth\u0026gt;\n\nredirect-gateway def1\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"open-vpn-연결\"\u003eOpen VPN 연결\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003eMac OS 에서는 \u003ccode\u003etunnel blick\u003c/code\u003e 을 사용\n\u003cul\u003e\n\u003cli\u003e설치를 위해서는 아래의 스크립트 실행\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003ebrew cask install tunnelblick\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ch4 id=\"라우팅-정보-확인\"\u003e라우팅 정보 확인\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003enetstat\u003c/code\u003e 을 이용하여 라우팅 정보 확인\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003etun\u003c/code\u003e 인터페이스와 일부 라우터가 추가된 것을 확인\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003enetstat -nr\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003eDestination\u003c/th\u003e\n\u003cth\u003eGateway\u003c/th\u003e\n\u003cth\u003eGenmask\u003c/th\u003e\n\u003cth\u003eFlags\u003c/th\u003e\n\u003cth\u003eMSS\u003c/th\u003e\n\u003cth\u003eWindow\u003c/th\u003e\n\u003cth\u003eirtt\u003c/th\u003e\n\u003cth\u003eIface\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e128.0.0.0\u003c/td\u003e\n\u003ctd\u003e192.168.255.5\u003c/td\u003e\n\u003ctd\u003e128.0.0.0\u003c/td\u003e\n\u003ctd\u003eUG\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003etun0\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e192.168.255.1\u003c/td\u003e\n\u003ctd\u003e192.168.255.5\u003c/td\u003e\n\u003ctd\u003e255.255.255.255\u003c/td\u003e\n\u003ctd\u003eUGH\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003etun0\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e192.168.255.5\u003c/td\u003e\n\u003ctd\u003e0.0.0.0\u003c/td\u003e\n\u003ctd\u003e255.255.255.255\u003c/td\u003e\n\u003ctd\u003eUH\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003etun0\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch4 id=\"라우팅-정보-수정\"\u003e라우팅 정보 수정\u003c/h4\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"/infra/docker/docker-compose/\" \u003e도커 네트워크 생성\u003c/a\u003e에서 \u003ccode\u003e192.168.100.0/24\u003c/code\u003e 로 네트워크를 생성하였고, 해당 트래픽을 \u003ccode\u003etun0\u003c/code\u003e 인터페이스로 라우팅을 수행\n\u003cul\u003e\n\u003cli\u003e라우팅 테이블을 수정하는 작업인데, 간단하게는 \u003ccode\u003eroute\u003c/code\u003e 명령어를 통해서 수행할 수 있음.\u003c/li\u003e\n\u003cli\u003e본 섹션에서는 \u003ccode\u003eovpn\u003c/code\u003e 파일을 수정하는 방법에 대해서 설명\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-text\" data-lang=\"text\"\u003eclient\nnobind\ndev tun\nremote-cert-tls server\n\nremote localhost 1194 udp\n\n\u0026lt;key\u0026gt;\n-----BEGIN PRIVATE KEY-----\n... 생략 ...\n-----END PRIVATE KEY-----\n\u0026lt;/key\u0026gt;\n\u0026lt;cert\u0026gt;\n-----BEGIN CERTIFICATE-----\n... 생략 ...\n-----END CERTIFICATE-----\n\u0026lt;/cert\u0026gt;\n\u0026lt;ca\u0026gt;\n-----BEGIN CERTIFICATE-----\n... 생략 ...\n-----END CERTIFICATE-----\n\u0026lt;/ca\u0026gt;\nkey-direction 1\n\u0026lt;tls-auth\u0026gt;\n#\n# 2048 bit OpenVPN static key\n#\n-----BEGIN OpenVPN Static key V1-----\n... 생략 ...\n-----END OpenVPN Static key V1-----\n\u0026lt;/tls-auth\u0026gt;\n\nroute 192.168.100.0 255.255.255.0\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e\u003c!--list-separator--\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003e라우팅 테이블 확인\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e해당 대역에 대한 라우팅 정보가 추가된 것을 확인\u003c/li\u003e\n\u003c/ul\u003e\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003eDestination\u003c/th\u003e\n\u003cth\u003eGateway\u003c/th\u003e\n\u003cth\u003eGenmask\u003c/th\u003e\n\u003cth\u003eFlags\u003c/th\u003e\n\u003cth\u003eMSS\u003c/th\u003e\n\u003cth\u003eWindow\u003c/th\u003e\n\u003cth\u003eirtt\u003c/th\u003e\n\u003cth\u003eIface\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e192.168.100.0\u003c/td\u003e\n\u003ctd\u003e192.168.255.5\u003c/td\u003e\n\u003ctd\u003e255.255.255.0\u003c/td\u003e\n\u003ctd\u003eUG\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003etun0\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e192.168.255.1\u003c/td\u003e\n\u003ctd\u003e192.168.255.5\u003c/td\u003e\n\u003ctd\u003e255.255.255.255\u003c/td\u003e\n\u003ctd\u003eUGH\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003etun0\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e192.168.255.5\u003c/td\u003e\n\u003ctd\u003e0.0.0.0\u003c/td\u003e\n\u003ctd\u003e255.255.255.255\u003c/td\u003e\n\u003ctd\u003eUH\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003e0\u003c/td\u003e\n\u003ctd\u003etun0\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n"},{id:19,href:"https://hackartists.github.io/infra/docker/docker-dns/",title:"도커 DNS 활용편",description:"This page explains how to connect to containers with thier name.",content:"\u003ch2 id=\"목표\"\u003e목표\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e도커 컨테이너들 간에는 네트워크 alias 로 통신이 가능하지만, 호스트 머신에서는 컨테이너와 통신하기가 어려움.\n\u003cul\u003e\n\u003cli\u003e매번 변하는 도커들의 IP 를 조회해서 관리하기가 어려움.\u003c/li\u003e\n\u003cli\u003e고정 IP로 지정할 수도 있으나, 이런 경우 해당 네트워크의 모든 컨테이너의 IP 를 관리해야 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"동작-원리\"\u003e동작 원리\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e도커 이름을 풀이해 줄 수 있는 DNS 서버를 개발\n\u003cul\u003e\n\u003cli\u003e해당 서버의 동작은 아래와 같음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003cfigure\u003e\n    \u003cimg src=\"/ox-hugo/docker-dns.png\"/\u003e \n\u003c/figure\u003e\n\n\u003ch2 id=\"사전-준비-사항\"\u003e사전 준비 사항\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003e본 섹션은 호스트 머신과 도커 컨테이너가 직접적인 통신이 가능해야 함.\n\u003cul\u003e\n\u003cli\u003eMac OS는 \u003ca class=\"link\" href=\"/infra/docker/docker-vpn/\" \u003e도커 VPN 활용편\u003c/a\u003e을 통해서 직접적인 통신이 가능한 상태여야 함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id=\"도커-dns-구축\"\u003e도커 DNS 구축\u003c/h2\u003e\n\u003ch3 id=\"도커-dns-설정\"\u003e도커 DNS 설정\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ehackartist/docker-dns\u003c/code\u003e 이미지를 사용\n\u003cul\u003e\n\u003cli\u003e도커 및 쿠버네티스(Kubernetes) DNS 기능 제공\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003ecluster.local.\u003c/code\u003e 쿠버네티스 검색도메인 제공\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003edocker-compose\u003c/code\u003e 에 아래의 컨테이너 정보 추가\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003e/var/run/docker.sock\u003c/code\u003e 은 해당 DNS 는 도커 명령어 인터페이스(CLI) 를 통해서 컨테이너 이름을 IP 주소로 변환\u003c/li\u003e\n\u003cli\u003e이 과정에서 도커 디먼과 통신을 해야하기 때문에 해당 주소를 마운트 해야함.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-docker-compose\" data-lang=\"docker-compose\"\u003edns:\n  restart: always\n  container_name: dns\n  image: hackartist/docker-dns:latest\n  volumes:\n    - /var/run/docker.sock:/var/run/docker.sock\n  ports:\n    - 53:53/udp\n  environment:\n    - ENABLE_K8S_DNS_LOOKUP=false\n    - FALLBACK_DNS=8.8.8.8\n\u003c/code\u003e\u003c/pre\u003e\u003ch3 id=\"dns-주소-변경\"\u003eDNS 주소 변경\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e호스트 머신의 DNS 주소를 \u003ccode\u003e127.0.0.1\u003c/code\u003e 로 변경\n\u003cul\u003e\n\u003cli\u003e구축한 도커 DNS 를 기본 DNS로 사용하도록 설정\u003c/li\u003e\n\u003cli\u003e\u003ccode\u003e/etc/resolv.conf\u003c/code\u003e 의 내용 또는 네트워크 설정에서 변경할 수 있음.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cpre\u003e\u003ccode class=\"language-conf\" data-lang=\"conf\"\u003enameserver 127.0.0.1\nnameserver 10.96.0.10\nnameserver 8.8.8.8\n\u003c/code\u003e\u003c/pre\u003e\u003ch3 id=\"dns-서버-테스트\"\u003eDNS 서버 테스트\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003ccode\u003enslookup\u003c/code\u003e 을 통해서 테스트할 수 있음.\n\u003cul\u003e\n\u003cli\u003e서버가 \u003ccode\u003e127.0.0.1\u003c/code\u003e 로 나오면 정상 변경이 적용\n\u003cul\u003e\n\u003cli\u003e변경이 되지 않은 경우에는 네트워크를 비활성화 후에 다시 활성화하여 확인\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e서버가 \u003ccode\u003e127.0.0.1\u003c/code\u003e 로 정상적으로 변경되었는데, 검색이 안되면 아래의 내용 확인\n\u003cul\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"#%eb%8f%84%ec%bb%a4-dns-%ec%84%a4%ec%a0%95\" \u003e도커 DNS 설정\u003c/a\u003e에서 이름을 \u003ccode\u003econtainer_name\u003c/code\u003e 을 \u003ccode\u003edns\u003c/code\u003e 로 했는지 확인\u003c/li\u003e\n\u003cli\u003e\u003ca class=\"link\" href=\"#%eb%8f%84%ec%bb%a4-dns-%ec%84%a4%ec%a0%95\" \u003e도커 DNS 설정\u003c/a\u003e에서 볼륨 마운트를 정상적으로 했는지 확인\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c!--listend--\u003e\n\u003cdiv class=\"highlight\"\u003e\u003cpre class=\"chroma\"\u003e\u003ccode class=\"language-bash\" data-lang=\"bash\"\u003eServer:\t\t127.0.0.1\nAddress:\t127.0.0.1#53\n\nName:\tdns\nAddress: 172.51.0.3\n\u003c/code\u003e\u003c/pre\u003e\u003c/div\u003e"},{id:20,href:"https://hackartists.github.io/design/",title:"Designs",description:null,content:""},{id:21,href:"https://hackartists.github.io/infra/",title:"Infras",description:null,content:""},{id:22,href:"https://hackartists.github.io/blog/",title:"Blogs",description:null,content:""},{id:23,href:"https://hackartists.github.io/emacs/",title:"Emacs",description:null,content:""},{id:24,href:"https://hackartists.github.io/devel/",title:"Devels",description:null,content:""},{id:25,href:"https://hackartists.github.io/ops/",title:"Ops",description:null,content:""},];index.add(docs);userinput.addEventListener('input',show_results,true);suggestions.addEventListener('click',accept_suggestion,true);function show_results(){var value=this.value;var results=index.search(value,5);var entry,childs=suggestions.childNodes;var i=0,len=results.length;suggestions.classList.remove('d-none');results.forEach(function(page){entry=document.createElement('div');entry.innerHTML='<a href><span></span><span></span></a>';a=entry.querySelector('a'),t=entry.querySelector('span:first-child'),d=entry.querySelector('span:nth-child(2)');a.href=page.href;t.textContent=page.title;d.textContent=page.description;suggestions.appendChild(entry);});while(childs.length>len){suggestions.removeChild(childs[i])}}
function accept_suggestion(){while(suggestions.lastChild){suggestions.removeChild(suggestions.lastChild);}
return false;}}());